-- Berçário | 1º Semestre | 7 seções | 40 checklist | 23 texto
INSERT INTO qsi_templates (serie, semestre, titulo, subtitulo, sections)
VALUES ('Berçário', 1, 'Questionário de Sondagem — Berçário', 'Instrumento para levantamento do desenvolvimento da criança no início do ano letivo', '[{"title": "1. Vínculo, Adaptação e Segurança Emocional", "bncc": "BNCC: EI01EO01, EI01EO02, EI01EO03, EI01EO05 | Campos: O eu, o outro e o nós", "checklist": ["Aceita o colo e o toque de adultos de referência na escola", "Demonstra sinais de reconhecimento da professora (olhar, sorriso, movimentos corporais)", "Acalma-se com estratégias de acolhimento: colo, balanço, voz suave, música", "Expressa desconforto por meio de choro, movimentos ou vocalizações", "Aceita a permanência na escola sem choro prolongado após período de adaptação", "Demonstra reação ao próprio nome quando chamado", "Reage à presença e à ausência de figuras de apego"], "prompts": ["Conte como foi o processo de adaptação deste bebê. Como reagiu nos primeiros dias? Houve choro prolongado? Como a família participou?", "O bebê já demonstra preferência por algum adulto ou colega? Como se manifesta?", "Observações sobre vínculo, adaptação e segurança emocional:"]}, {"title": "2. Desenvolvimento Sensório-Motor e Exploração Corporal", "bncc": "BNCC: EI01CG01, EI01CG02, EI01CG03, EI01CG05 | Campos: Corpo, gestos e movimentos", "checklist": ["Sustenta a cabeça quando colocado de bruços (conforme idade)", "Rola de costas para barriga ou vice-versa (conforme idade)", "Senta-se com apoio ou sem apoio (conforme idade)", "Movimenta-se pelo espaço: arrasta-se, engatinha ou tenta ficar de pé (conforme idade)", "Segura objetos com as mãos e leva à boca para exploração", "Transfere objetos de uma mão para outra (conforme idade)", "Explora superfícies, texturas e materiais com as mãos e o corpo", "Responde a estímulos sensoriais: sons, luzes, texturas, movimentos"], "prompts": ["Descreva as conquistas motoras atuais do bebê. Qual é a forma principal de deslocamento? Há alguma particularidade?", "Como o bebê explora os materiais e brinquedos oferecidos? Demonstra preferência por algum tipo de estímulo sensorial?", "Observações sobre desenvolvimento sensório-motor e exploração corporal:"]}, {"title": "3. Alimentação, Sono, Higiene e Cuidados", "bncc": "BNCC: EI01EO05, EI01CG01, EI01CG04 | Campos: O eu, o outro e o nós; Corpo, gestos e movimentos", "checklist": ["Aceita alimentação oferecida pela professora (mamadeira, papa, fruta)", "Come alimentos pastosos conforme introdução alimentar indicada pela família", "Demonstra sinais de fome e saciedade", "Tem rotina de sono na escola (adormece com auxílio, dorme períodos adequados)", "Aceita a troca de fraldas e os cuidados de higiene", "Demonstra sinais de desconforto quando está molhado ou sujo"], "prompts": ["Descreva a rotina de alimentação do bebê na escola. Há restrições alimentares ou dificuldades observadas?", "Como é o sono do bebê na escola? Dorme com facilidade? Precisa de estratégias específicas para adormecer?", "Observações sobre alimentação, sono, higiene e cuidados:"]}, {"title": "4. Comunicação Pré-Verbal e Interação", "bncc": "BNCC: EI01EF01, EI01EF02, EI01EF03, EI01EF04, EI01EF06 | Campos: Escuta, fala, pensamento e imaginação; O eu, o outro e o nós", "checklist": ["Emite sons variados: gorjeios, guturais, balbucio (conforme idade)", "Vocaliza em resposta a estímulos sonoros ou à fala do adulto", "Direciona o olhar para o adulto quando ouve sua voz", "Reage a sons do ambiente (música, voz, objetos sonoros)", "Responde ao próprio nome com olhar ou movimento", "Demonstra atenção por breves períodos a canções ou brincadeiras vocais", "Observa e reage à presença de outros bebês", "Sorri em interações face a face"], "prompts": ["Quais formas de comunicação o bebê utiliza predominantemente (choro, gestos, balbucio, olhar, apontar)?", "O bebê demonstra interesse por histórias, canções e brincadeiras vocais? Como reage?", "Observações sobre comunicação pré-verbal e interação:"]}, {"title": "5. Exploração Sensorial, Curiosidade e Descobertas", "bncc": "BNCC: EI01ET01, EI01ET02, EI01ET03, EI01ET04, EI01ET05, EI01ET06 | Campos: Espaços, tempos, quantidades, relações e transformações; Traços, sons, cores e formas", "checklist": ["Explora materiais com as mãos e a boca: tecidos, potes, bolas, chocalhos", "Manipula objetos: segura, chacoalha, bate, solta (conforme idade)", "Observa movimentos, luzes e imagens com atenção", "Reage a estímulos novos com curiosidade ou estranhamento", "Explora diferentes texturas e consistências em atividades sensoriais", "Acompanha trajetórias de objetos com o olhar"], "prompts": ["Quais materiais e brinquedos mais atraem a atenção deste bebê? Ele demonstra curiosidade ativa?", "Como o bebê reage a experiências sensoriais novas (tinta, areia, gel, gelo, luzes, música)?", "Observações sobre exploração sensorial, curiosidade e descobertas:"]}, {"title": "6. Expressão Artística, Musical e Corporal", "bncc": "BNCC: EI01TS01, EI01TS02, EI01TS03, EI01CG01 | Campos: Traços, sons, cores e formas; Corpo, gestos e movimentos", "checklist": ["Reage a músicas e canções com expressões faciais ou movimentos corporais", "Explora instrumentos sonoros simples: chocalho, guizo", "Explora materiais plásticos oferecidos: tinta, massa, papel", "Observa e reage a estímulos visuais coloridos ou em movimento", "Demonstra prazer em brincadeiras de acalanto e balanço"], "prompts": ["Como o bebê reage a momentos musicais? Ele se movimenta, vocaliza, demonstra prazer?", "O bebê já teve contato com materiais como tinta ou massa? Como reagiu?", "Observações sobre expressão artística, musical e corporal:"]}, {"title": "CONSIDERAÇÕES GERAIS E SÍNTESE PARA O RELATÓRIO", "bncc": "", "checklist": [], "prompts": ["Quais são as conquistas mais marcantes deste bebê neste semestre?", "Em quais áreas você observa maior necessidade de atenção ou estimulação?", "Há algo no contexto familiar ou na saúde do bebê que influencia o desenvolvimento observado?", "Quais estratégias pedagógicas têm funcionado bem com este bebê?", "Há alguma observação que precise ser compartilhada com a coordenação ou família?"]}]'::jsonb);

-- Berçário | 2º Semestre | 7 seções | 48 checklist | 23 texto
INSERT INTO qsi_templates (serie, semestre, titulo, subtitulo, sections)
VALUES ('Berçário', 2, 'Questionário de Sondagem — Berçário', 'Instrumento para levantamento do desenvolvimento da criança ao final do ano letivo', '[{"title": "1. Vínculo, Adaptação e Segurança Emocional", "bncc": "BNCC: EI01EO01, EI01EO02, EI01EO03, EI01EO05 | Campos: O eu, o outro e o nós", "checklist": ["Demonstra vínculo com a professora de referência, buscando proximidade e conforto", "Diferencia adultos familiares de pessoas não conhecidas", "Acalma-se com ações de acolhimento: colo, voz, toque, música", "Aceita ser cuidado por outros adultos da escola além da referência principal", "Manifesta preferências por determinados adultos ou colegas", "Expressa desconforto, alegria, medo ou surpresa por meio de expressões faciais, choro ou vocalizações", "Demonstra reação ao próprio nome quando chamado", "Tolera breves momentos de espera quando avisado com gestos ou palavras pelo adulto"], "prompts": ["Conte como foi o processo de adaptação deste bebê. Como reagiu nos primeiros dias? Houve choro prolongado? Como a família participou?", "Como o bebê demonstra vínculo com os adultos e com os colegas ao final do semestre? Houve mudanças em relação ao início do ano?", "Observações sobre vínculo, adaptação e segurança emocional:"]}, {"title": "2. Desenvolvimento Sensório-Motor e Exploração Corporal", "bncc": "BNCC: EI01CG01, EI01CG02, EI01CG03, EI01CG05 | Campos: Corpo, gestos e movimentos", "checklist": ["Sustenta a cabeça com firmeza", "Rola de costas para barriga e vice-versa com autonomia", "Senta-se com apoio mínimo ou sem apoio", "Arrasta-se, engatinha ou se desloca pelo espaço de alguma forma", "Tenta ficar de pé com apoio em móveis ou adulto", "Transfere objetos de uma mão para outra", "Usa movimento de pinça para pegar objetos pequenos", "Explora objetos com as mãos, boca, pés e corpo todo", "Bate palmas, acena ou realiza gestos imitativos simples", "Responde a estímulos sensoriais variados: texturas, sons, luzes"], "prompts": ["Descreva as conquistas motoras atuais do bebê. Qual é a forma principal de deslocamento? Há alguma particularidade?", "Como o bebê explora os materiais e brinquedos oferecidos? Demonstra preferência por algum tipo de estímulo sensorial?", "Observações sobre desenvolvimento sensório-motor e exploração corporal:"]}, {"title": "3. Alimentação, Sono, Higiene e Cuidados", "bncc": "BNCC: EI01EO05, EI01CG01, EI01CG04 | Campos: O eu, o outro e o nós; Corpo, gestos e movimentos", "checklist": ["Aceita alimentação oferecida pela professora com boa aceitação", "Come alimentos pastosos e/ou sólidos conforme introdução alimentar", "Segura a mamadeira ou copo com ajuda ou sozinho (conforme idade)", "Tenta levar alimentos à boca com as mãos ou colher com apoio", "Tem rotina de sono estabelecida na escola", "Aceita a troca de fraldas sem desconforto significativo", "Colabora nas trocas movimentando o corpo quando solicitado", "Demonstra sinais de desconforto quando está molhado ou sujo"], "prompts": ["Descreva a rotina de alimentação do bebê na escola. Há restrições alimentares ou dificuldades observadas?", "Como é o sono do bebê na escola? Dorme com facilidade? Precisa de estratégias específicas para adormecer?", "Observações sobre alimentação, sono, higiene e cuidados:"]}, {"title": "4. Comunicação Pré-Verbal e Interação", "bncc": "BNCC: EI01EF01, EI01EF02, EI01EF03, EI01EF04, EI01EF06 | Campos: Escuta, fala, pensamento e imaginação; O eu, o outro e o nós", "checklist": ["Balbucia com variação de sons e sílabas (ma-ma, da-da, ba-ba)", "Vocaliza para chamar atenção ou expressar desejos", "Aponta ou direciona o olhar para objetos de interesse", "Compreende palavras simples do cotidiano (tchau, não, mamadeira, água)", "Responde ao próprio nome virando-se ou olhando para quem chamou", "Imita sons e gestos produzidos pelo adulto", "Demonstra atenção por breves períodos ao ouvir histórias, canções ou parlendas", "Interage com outros bebês por meio de olhar, toque, sons ou gest", "Sorri responsivamente em interações face a face"], "prompts": ["Quais formas de comunicação o bebê utiliza predominantemente (choro, gestos, balbucio, olhar, apontar)?", "O bebê demonstra interesse por histórias, canções e brincadeiras vocais? Como reage?", "Observações sobre comunicação pré-verbal e interação:"]}, {"title": "5. Exploração Sensorial, Curiosidade e Descobertas", "bncc": "BNCC: EI01ET01, EI01ET02, EI01ET03, EI01ET04, EI01ET05, EI01ET06 | Campos: Espaços, tempos, quantidades, relações e transformações; Traços, sons, cores e formas", "checklist": ["Explora materiais com curiosidade: tecidos, potes, tampas, bolas, livros de pano", "Manipula objetos com intenção: encaixa, empilha, puxa, chacoalha", "Repete ações que produzem efeitos interessantes (causa e efeito)", "Observa movimentos, luzes e imagens com atenção", "Explora diferentes texturas, temperaturas e consistências", "Demonstra preferência por determinados objetos ou brinquedos", "Acompanha trajetórias de objetos com o olhar"], "prompts": ["Quais materiais e brinquedos mais atraem a atenção deste bebê? Ele demonstra curiosidade ativa?", "Como o bebê reage a experiências sensoriais novas (tinta, areia, gel, gelo, luzes, música)?", "Observações sobre exploração sensorial, curiosidade e descobertas:"]}, {"title": "6. Expressão Artística, Musical e Corporal", "bncc": "BNCC: EI01TS01, EI01TS02, EI01TS03, EI01CG01 | Campos: Traços, sons, cores e formas; Corpo, gestos e movimentos", "checklist": ["Reage a músicas e canções com movimentos corporais, sorrisos ou vocalizações", "Explora instrumentos sonoros simples: chocalho, tambor, pandeirola", "Faz rabiscos com giz grosso, canetão ou tinta (conforme oportunidade)", "Explora materiais plásticos: massa, tinta, papel amassado", "Movimenta-se ao som de música, balançando o corpo ou batendo palmas", "Demonstra prazer em brincadeiras de roda, dança ou acalanto"], "prompts": ["Como o bebê reage a momentos musicais? Ele se movimenta, vocaliza, demonstra prazer?", "O bebê já explora materiais como tinta, giz ou massa? Descreva o que foi observado.", "Observações sobre expressão artística, musical e corporal:"]}, {"title": "CONSIDERAÇÕES GERAIS E SÍNTESE PARA O RELATÓRIO", "bncc": "", "checklist": [], "prompts": ["Quais são as conquistas mais marcantes deste bebê neste semestre?", "Em quais áreas você observa maior necessidade de atenção ou estimulação?", "Há algo no contexto familiar ou na saúde do bebê que influencia o desenvolvimento observado?", "Quais estratégias pedagógicas têm funcionado bem com este bebê?", "Há alguma observação que precise ser compartilhada com a coordenação ou família?"]}]'::jsonb);

-- Infantil 1 | 1º Semestre | 8 seções | 49 checklist | 26 texto
INSERT INTO qsi_templates (serie, semestre, titulo, subtitulo, sections)
VALUES ('Infantil 1', 1, 'Questionário de Sondagem — Infantil 1', 'Instrumento para levantamento do desenvolvimento da criança no início do ano letivo', '[{"title": "1. Vínculo, Identidade, Autonomia e Regulação Emocional", "bncc": "BNCC: EI01EO01, EI01EO02, EI01EO03, EI01EO04, EI01EO06 | Campos: O eu, o outro e o nós", "checklist": ["Aceita a permanência na escola e o adulto de referência", "Reconhece o próprio nome e reage quando chamada", "Expressa emoções por meio de expressões faciais, choro, gestos ou vocalizações", "Observa e interage com outros bebês/crianças por olhar ou toque", "Demonstra estranhamento na presença de pessoas não familiares", "Aceita breves separações do adulto de referência após adaptação", "Compreende orientações simples como ''não'', ''vem'', ''senta''", "Participa de momentos da rotina com apoio: lanche, roda, trocas"], "prompts": ["Conte como foi o processo de adaptação desta criança. Como reagiu nos primeiros dias? Há particularidades no vínculo com adultos ou colegas?", "Como a criança expressa suas emoções? Chora com frequência? Ri facilmente? Há algo marcante?", "Observações sobre vínculo, identidade, autonomia e regulação emocional:"]}, {"title": "2. Desenvolvimento Motor Amplo e Exploração do Espaço", "bncc": "BNCC: EI01CG01, EI01CG02, EI01CG03 | Campos: Corpo, gestos e movimentos", "checklist": ["Fica de pé com ou sem apoio", "Caminha com ou sem apoio (conforme desenvolvimento)", "Senta-se e levanta-se com autonomia", "Engatinha ou se desloca pelo espaço de alguma forma", "Sobe em superfícies baixas com apoio (almofadões, colchonetes)", "Empurra e puxa objetos pelo espaço", "Imita movimentos corporais simples: bater palmas, balançar", "Movimenta-se ao som de música"], "prompts": ["Descreva as conquistas motoras atuais desta criança. Já caminha? Como se desloca?", "Há alguma particularidade no desenvolvimento motor que você considera importante registrar?", "Observações sobre desenvolvimento motor amplo e exploração do espaço:"]}, {"title": "3. Coordenação Motora Fina e Manipulação", "bncc": "BNCC: EI01CG05, EI01TS02 | Campos: Corpo, gestos e movimentos; Traços, sons, cores e formas", "checklist": ["Segura objetos com a mão inteira (preensão palmar)", "Tenta usar pinça para pegar objetos menores", "Encaixa peças grandes em brinquedos de encaixe", "Empilha blocos ou copos com apoio", "Explora livros de pano ou cartonados folheando as páginas", "Rabisca com giz grosso ou canetão quando oferecido", "Bate objetos um no outro produzindo sons"], "prompts": ["Como é a manipulação de objetos pequenos? A criança já usa pinça? Há dificuldades observadas?", "A criança demonstra interesse por riscar, rabiscar ou pintar? Descreva.", "Observações sobre coordenação motora fina e manipulação:"]}, {"title": "4. Linguagem Oral, Comunicação e Compreensão", "bncc": "BNCC: EI01EF01, EI01EF02, EI01EF03, EI01EF04, EI01EF05, EI01EF06 | Campos: Escuta, fala, pensamento e imaginação", "checklist": ["Balbucia com variação de sílabas", "Compreende palavras simples do cotidiano", "Aponta para objetos ou pessoas quando quer algo", "Usa gestos comunicativos: acena, aponta, estende os braços", "Reage a canções, parlendas e brincadeiras vocais com atenção ou movimentos", "Demonstra atenção por breves momentos a histórias com imagens", "Tenta imitar sons ou palavras ditas pelo adulto", "Expressa desejos por meio de vocalizações e gestos"], "prompts": ["Quais palavras ou sons a criança já produz? Há palavras com significado claro?", "Como a criança se comunica para expressar desejos e necessidades? Dê exemplos do cotidiano.", "Observações sobre linguagem oral, comunicação e compreensão:"]}, {"title": "5. Alimentação, Sono, Higiene e Autonomia nos Cuidados", "bncc": "BNCC: EI01EO05, EI01CG04 | Campos: O eu, o outro e o nós; Corpo, gestos e movimentos", "checklist": ["Aceita alimentação oferecida (sólida e/ou pastosa conforme fase)", "Bebe água ou leite oferecido no copo ou mamadeira", "Demonstra sinais de fome e saciedade", "Aceita a troca de fraldas e cuidados de higiene", "Adormece na escola com ou sem estratégias de acalanto", "Colabora minimamente nos cuidados (estende a mão para lavar, por exemplo)"], "prompts": ["Descreva a relação da criança com a alimentação na escola. Há seletividade, resistência ou boa aceitação?", "Como é o sono da criança na escola? Há dificuldades? Quais estratégias funcionam?", "Observações sobre alimentação, sono, higiene e autonomia nos cuidados:"]}, {"title": "6. Exploração Sensorial, Investigação e Descobertas", "bncc": "BNCC: EI01ET01, EI01ET02, EI01ET03, EI01ET04, EI01ET05, EI01ET06 | Campos: Espaços, tempos, quantidades, relações e transformações", "checklist": ["Explora materiais diversos com curiosidade: potes, tampas, tecidos, bolas", "Repete ações que produzem efeitos interessantes", "Observa movimentos e trajetórias de objetos", "Coloca e tira objetos de recipientes", "Demonstra reação a estímulos novos: curiosidade, estranhamento", "Reconhece objetos do cotidiano (mamadeira, sapato, bola)"], "prompts": ["Quais materiais e experiências mais despertam a curiosidade desta criança?", "A criança demonstra comportamento investigativo? Dê um exemplo recente.", "Observações sobre exploração sensorial, investigação e descobertas:"]}, {"title": "7. Expressão Artística, Musical e Brincadeira Simbólica Inicial", "bncc": "BNCC: EI01TS01, EI01TS02, EI01TS03, EI01CG01 | Campos: Traços, sons, cores e formas; Corpo, gestos e movimentos", "checklist": ["Reage a músicas e canções com movimentos ou vocalizações", "Explora instrumentos sonoros: chocalho, guizo", "Explora tinta ou materiais plásticos quando oferecidos", "Rabisca com giz grosso ou canetão em suportes grandes", "Observa e manipula livros com interesse", "Imita ações simples dos adultos em contextos lúdicos"], "prompts": ["A criança demonstra prazer em atividades artísticas? Quais linguagens mais a atraem?", "Há sinais de início de brincadeira simbólica (faz de conta)? Descreva.", "Observações sobre expressão artística, musical e brincadeira simbólica:"]}, {"title": "CONSIDERAÇÕES GERAIS E SÍNTESE PARA O RELATÓRIO", "bncc": "", "checklist": [], "prompts": ["Quais são as conquistas mais marcantes desta criança neste semestre?", "Em quais áreas você observa maior necessidade de atenção ou estimulação?", "Há algo no contexto familiar ou na saúde da criança que influencia o desenvolvimento observado?", "Quais estratégias pedagógicas têm funcionado bem com esta criança?", "Há alguma observação que precise ser compartilhada com a coordenação ou família?"]}]'::jsonb);

-- Infantil 1 | 2º Semestre | 8 seções | 58 checklist | 26 texto
INSERT INTO qsi_templates (serie, semestre, titulo, subtitulo, sections)
VALUES ('Infantil 1', 2, 'Questionário de Sondagem — Infantil 1', 'Instrumento para levantamento do desenvolvimento da criança ao final do ano letivo', '[{"title": "1. Vínculo, Identidade, Autonomia e Regulação Emocional", "bncc": "BNCC: EI01EO01, EI01EO02, EI01EO03, EI01EO04, EI01EO06 | Campos: O eu, o outro e o nós", "checklist": ["Demonstra vínculo com adultos de referência e os procura em situações de desconforto", "Reconhece o próprio nome e reage quando chamada", "Reconhece-se em fotos e no espelho", "Expressa emoções básicas: alegria, raiva, tristeza, medo", "Interage com colegas por meio de olhar, gestos, toque ou imitação", "Demonstra preferência por determinados colegas ou brincadeiras", "Aceita breves separações do adulto de referência", "Compreende orientações simples como ''não'', ''vem'', ''senta''", "Participa de momentos da rotina com apoio: lanche, roda, trocas", "Aceita limítes básicos colocados pelo adulto, ainda que com resistência"], "prompts": ["Conte como foi o processo de adaptação desta criança. Como reagiu nos primeiros dias? Há particularidades no vínculo com adultos ou colegas?", "Ao longo do semestre, houve avanços no comportamento emocional e social da criança? Dê exemplos.", "Observações sobre vínculo, identidade, autonomia e regulação emocional:"]}, {"title": "2. Desenvolvimento Motor Amplo e Exploração do Espaço", "bncc": "BNCC: EI01CG01, EI01CG02, EI01CG03 | Campos: Corpo, gestos e movimentos", "checklist": ["Caminha com equilíbrio crescente em superfícies regulares", "Sobe e desce de móveis baixos, almofadas ou rampas com apoio", "Tenta correr, ainda com passos instáveis", "Chuta bola quando posicionada à sua frente", "Agacha-se e levanta-se sem perder o equilíbrio", "Empurra e puxa objetos pelo espaço (carrinhos, caixas)", "Sobe pequenos degraus com apoio", "Imita movimentos corporais simples: bater palmas, levantar braços, balançar", "Dança ou se movimenta ao som de música"], "prompts": ["Descreva as conquistas motoras atuais desta criança. Já caminha? Como se desloca?", "Há alguma particularidade no desenvolvimento motor que você considera importante registrar?", "Observações sobre desenvolvimento motor amplo e exploração do espaço:"]}, {"title": "3. Coordenação Motora Fina e Manipulação", "bncc": "BNCC: EI01CG05, EI01TS02 | Campos: Corpo, gestos e movimentos; Traços, sons, cores e formas", "checklist": ["Segura objetos com a mão inteira (preensão palmar)", "Usa pinça inferior ou superior para pegar objetos pequenos", "Encaixa peças simples em buracos ou caixas", "Empilha dois ou mais blocos", "Abre e fecha tampas, potes e caixas", "Rabisca com giz grosso, canetão ou com os dedos na tinta", "Folheia páginas grossas de livros", "Puxa, empurra e gira peças de brinquedos"], "prompts": ["Como é a manipulação de objetos pequenos? A criança já usa pinça? Há dificuldades observadas?", "A criança demonstra interesse por riscar, rabiscar ou pintar? Descreva.", "Observações sobre coordenação motora fina e manipulação:"]}, {"title": "4. Linguagem Oral, Comunicação e Compreensão", "bncc": "BNCC: EI01EF01, EI01EF02, EI01EF03, EI01EF04, EI01EF05, EI01EF06 | Campos: Escuta, fala, pensamento e imaginação", "checklist": ["Fala palavras isoladas com significado (mamã, papa, água, dá)", "Compreende orientações simples: ''pega'', ''traz'', ''dá pra mim''", "Aponta para objetos, pessoas ou lugares para comunicar desejos", "Usa gestos comunicativos: acena, aponta, nega com a cabeça", "Imita sons de animais, veículos ou objetos", "Tenta repetir palavras ditas pelo adulto", "Demonstra atenção a histórias curtas com imagens", "Participa de canções e brincadeiras cantadas com gestos", "Nomeia figuras familiares em livros ou cartazes"], "prompts": ["Quais palavras ou sons a criança já produz? Há palavras com significado claro?", "Como a criança se comunica para expressar desejos e necessidades? Dê exemplos do cotidiano.", "Observações sobre linguagem oral, comunicação e compreensão:"]}, {"title": "5. Alimentação, Sono, Higiene e Autonomia nos Cuidados", "bncc": "BNCC: EI01EO05, EI01CG04 | Campos: O eu, o outro e o nós; Corpo, gestos e movimentos", "checklist": ["Come alimentos sólidos e pastosos com boa aceitação", "Tenta usar colher sozinha, ainda derramando", "Bebe água no copo com apoio ou sozinha", "Demonstra preferências alimentares claras", "Aceita a higienização das mãos e do rosto após refeições", "Colabora nas trocas de fraldas, levantando pernas ou segurando-se", "Adormece na escola com rotina estabelecida", "Demonstra sinais quando precisa ser trocada"], "prompts": ["Descreva a relação da criança com a alimentação na escola. Há seletividade, resistência ou boa aceitação?", "Como é o sono da criança na escola? Há dificuldades? Quais estratégias funcionam?", "Observações sobre alimentação, sono, higiene e autonomia nos cuidados:"]}, {"title": "6. Exploração Sensorial, Investigação e Descobertas", "bncc": "BNCC: EI01ET01, EI01ET02, EI01ET03, EI01ET04, EI01ET05, EI01ET06 | Campos: Espaços, tempos, quantidades, relações e transformações", "checklist": ["Explora materiais diversos com curiosidade: areia, água, massa, tinta", "Observa e repete ações que produzem efeitos (causa e efeito)", "Empilha, encaixa, enfileira, derruba e reconstrói com intenção", "Demonstra preferência por determinados brinquedos ou materiais", "Diferencia grande e pequeno em situações concretas", "Reconhece objetos do cotidiano e sabe sua função básica", "Acompanha sequências muito simples da rotina (primeiro lanche, depois parque)"], "prompts": ["Quais materiais e experiências mais despertam a curiosidade desta criança?", "A criança demonstra comportamento investigativo? Dê um exemplo recente.", "Observações sobre exploração sensorial, investigação e descobertas:"]}, {"title": "7. Expressão Artística, Musical e Brincadeira Simbólica Inicial", "bncc": "BNCC: EI01TS01, EI01TS02, EI01TS03, EI01CG01 | Campos: Traços, sons, cores e formas; Corpo, gestos e movimentos", "checklist": ["Participa de canções e brincadeiras cantadas com gestos e movimentos", "Explora instrumentos sonoros: chocalho, pandeirola, tambor", "Rabisca com prazer em suportes variados", "Explora tinta com os dedos, mãos e pés", "Observa produções visuais e demonstra interesse por cores e formas", "Inicia brincadeira de faz de conta simples: finge dar comidinha, ninar boneca", "Demonstra prazer em ouvir histórias e manipular livros"], "prompts": ["A criança demonstra prazer em atividades artísticas? Quais linguagens mais a atraem?", "Há sinais de início de brincadeira simbólica (faz de conta)? Descreva.", "Observações sobre expressão artística, musical e brincadeira simbólica:"]}, {"title": "CONSIDERAÇÕES GERAIS E SÍNTESE PARA O RELATÓRIO", "bncc": "", "checklist": [], "prompts": ["Quais são as conquistas mais marcantes desta criança neste semestre?", "Em quais áreas você observa maior necessidade de atenção ou estimulação?", "Há algo no contexto familiar ou na saúde da criança que influencia o desenvolvimento observado?", "Quais estratégias pedagógicas têm funcionado bem com esta criança?", "Há alguma observação que precise ser compartilhada com a coordenação ou família?"]}]'::jsonb);

-- Infantil 2 | 1º Semestre | 8 seções | 49 checklist | 26 texto
INSERT INTO qsi_templates (serie, semestre, titulo, subtitulo, sections)
VALUES ('Infantil 2', 1, 'Questionário de Sondagem — Infantil 2', 'Instrumento para levantamento do desenvolvimento da criança no início do ano letivo', '[{"title": "1. Identidade, Autonomia, Convivência e Regulação Emocional", "bncc": "BNCC: EI02EO01, EI02EO02, EI02EO03, EI02EO04, EI02EO06 | Campos: O eu, o outro e o nós", "checklist": ["Aceita a permanência na escola após período de adaptação", "Diz o próprio nome quando perguntada", "Reconhece-se em fotos e no espelho", "Expressa emoções por meio de choro, gestos, palavras ou expressões faciais", "Interage com colegas por meio de olhar, gestos e brincadeiras paralelas", "Compreende orientações simples dadas pelo adulto", "Aceita a rotina básica com apoio: lanche, roda, trocas, parque", "Procura o adulto quando precisa de ajuda ou conforto"], "prompts": ["Conte como foi o processo de adaptação. Como a criança se relaciona com adultos e colegas?", "Como a criança expressa suas emoções no dia a dia? Há algo que chama atenção?", "Observações sobre identidade, autonomia, convivência e regulação emocional:"]}, {"title": "2. Coordenação Motora Ampla e Esquema Corporal", "bncc": "BNCC: EI02CG01, EI02CG02, EI02CG03 | Campos: Corpo, gestos e movimentos", "checklist": ["Caminha com equilíbrio em superfícies regulares", "Corre com passos ainda instáveis", "Sobe em móveis baixos e degraus com apoio", "Agacha-se e levanta-se sem perder o equilíbrio", "Chuta bola quando posicionada à frente", "Imita movimentos corporais simples", "Identifica partes do corpo quando nomeadas", "Movimenta-se ao som de música"], "prompts": ["Há alguma particularidade no desenvolvimento motor desta criança? Inseguranças, avanços, necessidade de apoio?", "Como a criança se movimenta em espaços abertos (parque, pátio)? Demonstra confiança?", "Observações sobre coordenação motora ampla e esquema corporal:"]}, {"title": "3. Coordenação Motora Fina e Manipulação", "bncc": "BNCC: EI02CG05, EI02TS02 | Campos: Corpo, gestos e movimentos; Traços, sons, cores e formas", "checklist": ["Segura objetos com preensão palmar", "Encaixa peças grandes em brinquedos de encaixe", "Empilha blocos (2-3 peças)", "Rabisca com giz grosso ou canetão", "Amassa e manipula massinha", "Folheia páginas de livros cartonados", "Explora materiais com as mãos: cola, tinta, papel"], "prompts": ["Como é a preensão da criança ao segurar lápis ou giz? Ela demonstra dificuldades em atividades manuais?", "Quais atividades de manipulação mais despertam o interesse da criança?", "Observações sobre coordenação motora fina e manipulação:"]}, {"title": "4. Linguagem Oral, Comunicação e Narrativa Inicial", "bncc": "BNCC: EI02EF01, EI02EF02, EI02EF03, EI02EF04, EI02EF05, EI02EF06, EI02EF07 | Campos: Escuta, fala, pensamento e imaginação", "checklist": ["Fala palavras isoladas ou junta duas palavras", "Nomeia objetos e pessoas familiares", "Compreende orientações simples de uma etapa", "Aponta e nomeia figuras em livros", "Usa gestos e palavras para se comunicar", "Participa de canções e brincadeiras cantadas", "Demonstra atenção a histórias curtas com imagens", "Tenta repetir palavras novas"], "prompts": ["Como você descreveria a comunicação oral desta criança? Ela se expressa por iniciativa própria?", "A criança demonstra interesse por histórias e livros? Como reage nos momentos de leitura?", "Observações sobre linguagem oral, comunicação e narrativa:"]}, {"title": "5. Traçado, Rabisco, Pintura e Expressão Visual", "bncc": "BNCC: EI02TS02, EI02TS03, EI02CG05 | Campos: Traços, sons, cores e formas; Corpo, gestos e movimentos", "checklist": ["Rabisca livremente em suportes variados", "Explora tinta com as mãos e dedos", "Escolhe cores por preferência", "Demonstra prazer em atividades de pintura e desenho", "Aceita manipular cola, tinta e materiais plásticos", "Faz traços amplos sem direção definida"], "prompts": ["O que costuma aparecer nos rabiscos e produções visuais desta criança? Ela nomeia o que faz?", "Como a criança reage a materiais artísticos novos (tinta, cola, massa, sucata)?", "Observações sobre traçado, rabisco, pintura e expressão visual:"]}, {"title": "6. Exploração do Espaço, Quantidade, Formas e Noções Iniciais", "bncc": "BNCC: EI02ET01, EI02ET04, EI02ET05, EI02ET06, EI02ET07, EI02ET08 | Campos: Espaços, tempos, quantidades, relações e transformações", "checklist": ["Diferencia grande e pequeno em situações muito concretas", "Coloca e tira objetos de recipientes (dentro/fora)", "Reconhece momentos da rotina: hora do lanche, hora do parque", "Empilha e enfileira objetos", "Encaixa formas em brinquedos simples", "Observa e compara objetos por características visuais"], "prompts": ["A criança demonstra compreender a rotina do dia? Ela antecipa o que vem a seguir?", "Como a criança reage a atividades de classificação e encaixe?", "Observações sobre exploração do espaço, quantidade, formas e noções iniciais:"]}, {"title": "7. Expressão Musical, Corporal e Brincadeira Simbólica", "bncc": "BNCC: EI02TS01, EI02TS03, EI02CG01, EI02EF06 | Campos: Traços, sons, cores e formas; Corpo, gestos e movimentos; Escuta, fala, pensamento e imaginação", "checklist": ["Participa de canções com gestos e movimentos", "Explora instrumentos sonoros simples", "Movimenta-se ao som de música", "Inicia brincadeira de faz de conta simples: finge dar comida, ninar boneca", "Imita ações dos adultos em brincadeiras", "Demonstra prazer em momentos musicais e de história"], "prompts": ["Como a criança se engaja no faz de conta? Ela cria enredos, usa objetos de forma imaginativa?", "Quais linguagens artísticas mais atraem esta criança (música, dança, teatro, artes visuais)?", "Observações sobre expressão musical, corporal e brincadeira simbólica:"]}, {"title": "CONSIDERAÇÕES GERAIS E SÍNTESE PARA O RELATÓRIO", "bncc": "", "checklist": [], "prompts": ["Quais são os pontos fortes mais marcantes desta criança neste semestre?", "Em quais áreas você observa maior necessidade de atenção ou estimulação?", "Há algo no contexto familiar ou nas interações sociais que influencia o desenvolvimento observado?", "Quais estratégias pedagógicas têm funcionado bem com esta criança?", "Há alguma observação sobre saúde, comportamento ou desenvolvimento que precise ser compartilhada com a coordenação ou família?"]}]'::jsonb);

-- Infantil 2 | 2º Semestre | 8 seções | 57 checklist | 26 texto
INSERT INTO qsi_templates (serie, semestre, titulo, subtitulo, sections)
VALUES ('Infantil 2', 2, 'Questionário de Sondagem — Infantil 2', 'Instrumento para levantamento do desenvolvimento da criança ao final do ano letivo', '[{"title": "1. Identidade, Autonomia, Convivência e Regulação Emocional", "bncc": "BNCC: EI02EO01, EI02EO02, EI02EO03, EI02EO04, EI02EO06 | Campos: O eu, o outro e o nós", "checklist": ["Diz o próprio nome e reconhece-se em fotos", "Identifica colegas e adultos de referência pelo nome", "Participa de rodas e momentos coletivos, permanecendo por períodos progressivos", "Demonstra preferências por brinquedos, colegas e atividades", "Expressa emoções básicas: alegria, raiva, tristeza, medo", "Aceita compartilhar brinquedos com mediação do adulto", "Compreende combinados simples da turma com apoio", "Procura o adulto diante de conflitos ou desconforto", "Realiza parte da rotina com apoio: guardar materiais, sentar para lanche, lavar mãos", "Tolera pequenas frustrações com ajuda do adulto"], "prompts": ["Conte como foi o processo de adaptação. Como a criança se relaciona com adultos e colegas?", "Descreva como a criança lida com situações de frustração ou conflito. Há estratégias que funcionam bem?", "Observações sobre identidade, autonomia, convivência e regulação emocional:"]}, {"title": "2. Coordenação Motora Ampla e Esquema Corporal", "bncc": "BNCC: EI02CG01, EI02CG02, EI02CG03 | Campos: Corpo, gestos e movimentos", "checklist": ["Corre com coordenação básica em espaços abertos", "Pula com os dois pés juntos", "Sobe e desce escadas com apoio, alternando ou não os pés", "Chuta bola com direção aproximada", "Anda em superfícies estreitas ou elevadas com apoio", "Imita movimentos e posições corporais em brincadeiras", "Reconhece partes do corpo: cabeça, mãos, pés, barriga", "Movimenta-se ao som de música com coordenação crescente"], "prompts": ["Há alguma particularidade no desenvolvimento motor desta criança? Inseguranças, avanços, necessidade de apoio?", "Como a criança se movimenta em espaços abertos (parque, pátio)? Demonstra confiança?", "Observações sobre coordenação motora ampla e esquema corporal:"]}, {"title": "3. Coordenação Motora Fina e Manipulação", "bncc": "BNCC: EI02CG05, EI02TS02 | Campos: Corpo, gestos e movimentos; Traços, sons, cores e formas", "checklist": ["Segura lápis, giz ou pincel com preensão palmar ou digital imatura", "Encaixa peças em brinquedos de encaixe e quebra-cabeças simples", "Empilha blocos e construções simples", "Amassa, enrola e aperta massinha com intenção", "Rasga papel com as mãos", "Folheia páginas de livros individualmente", "Cola materiais com ajuda", "Abre e fecha potes, tampas e caixas"], "prompts": ["Como é a preensão da criança ao segurar lápis ou giz? Ela demonstra dificuldades em atividades manuais?", "Quais atividades de manipulação mais despertam o interesse da criança?", "Observações sobre coordenação motora fina e manipulação:"]}, {"title": "4. Linguagem Oral, Comunicação e Narrativa Inicial", "bncc": "BNCC: EI02EF01, EI02EF02, EI02EF03, EI02EF04, EI02EF05, EI02EF06, EI02EF07 | Campos: Escuta, fala, pensamento e imaginação", "checklist": ["Fala frases de duas ou mais palavras", "Nomeia objetos, pessoas e ações do cotidiano", "Responde perguntas simples: ''o que é isso?'', ''quem é?''", "Compreende histórias curtas com apoio de imagens", "Relata fatos muito recentes com apoio", "Pede o que deseja usando palavras ou combinações de palavras", "Participa de canções e repete refrões conhecidos", "Amplia vocabulário gradualmente", "Demonstra atenção a histórias lidas pelo adulto"], "prompts": ["Como você descreveria a comunicação oral desta criança? Ela se expressa por iniciativa própria?", "A criança demonstra interesse por histórias e livros? Como reage nos momentos de leitura?", "Observações sobre linguagem oral, comunicação e narrativa:"]}, {"title": "5. Traçado, Rabisco, Pintura e Expressão Visual", "bncc": "BNCC: EI02TS02, EI02TS03, EI02CG05 | Campos: Traços, sons, cores e formas; Corpo, gestos e movimentos", "checklist": ["Rabisca com intenção, ocupando o espaço do papel", "Nomeia rabiscos ou desenhos quando perguntada", "Explora tinta com pincel, dedos, esponja e outros instrumentos", "Reconhece e nomeia algumas cores", "Cola materiais com ajuda, posicionando de forma aleatória", "Faz traços variados: retos, curvos, circulares", "Demonstra prazer em atividades artísticas"], "prompts": ["O que costuma aparecer nos rabiscos e produções visuais desta criança? Ela nomeia o que faz?", "Como a criança reage a materiais artísticos novos (tinta, cola, massa, sucata)?", "Observações sobre traçado, rabisco, pintura e expressão visual:"]}, {"title": "6. Exploração do Espaço, Quantidade, Formas e Noções Iniciais", "bncc": "BNCC: EI02ET01, EI02ET04, EI02ET05, EI02ET06, EI02ET07, EI02ET08 | Campos: Espaços, tempos, quantidades, relações e transformações", "checklist": ["Diferencia grande e pequeno em situações concretas", "Identifica referências espaciais simples: dentro/fora, em cima/embaixo", "Reconhece a rotina básica do dia: lanche, parque, história, saída", "Agrupa objetos iguais por cor ou tipo", "Conta mecanicamente até 2 ou 3 com apoio", "Encaixa formas geométricas em brinquedos de encaixe", "Monta quebra-cabeças simples de poucas peças", "Percebe diferenças entre objetos: cor, tamanho, forma"], "prompts": ["A criança demonstra compreender a rotina do dia? Ela antecipa o que vem a seguir?", "Como a criança reage a atividades de classificação e encaixe?", "Observações sobre exploração do espaço, quantidade, formas e noções iniciais:"]}, {"title": "7. Expressão Musical, Corporal e Brincadeira Simbólica", "bncc": "BNCC: EI02TS01, EI02TS03, EI02CG01, EI02EF06 | Campos: Traços, sons, cores e formas; Corpo, gestos e movimentos; Escuta, fala, pensamento e imaginação", "checklist": ["Participa de canções, parlendas e brincadeiras cantadas com gestos", "Explora instrumentos musicais simples com intenção", "Dança e se movimenta ao som de música com prazer", "Participa de brincadeiras de faz de conta: dar comida, ninar, passear", "Atribui funções a objetos: usa bloco como telefone, caixa como carro", "Imita ações e falas dos adultos em brincadeiras", "Demonstra prazer em momentos de história, música e teatro"], "prompts": ["Como a criança se engaja no faz de conta? Ela cria enredos, usa objetos de forma imaginativa?", "Quais linguagens artísticas mais atraem esta criança (música, dança, teatro, artes visuais)?", "Observações sobre expressão musical, corporal e brincadeira simbólica:"]}, {"title": "CONSIDERAÇÕES GERAIS E SÍNTESE PARA O RELATÓRIO", "bncc": "", "checklist": [], "prompts": ["Quais são os pontos fortes mais marcantes desta criança neste semestre?", "Em quais áreas você observa maior necessidade de atenção ou estimulação?", "Há algo no contexto familiar ou nas interações sociais que influencia o desenvolvimento observado?", "Quais estratégias pedagógicas têm funcionado bem com esta criança?", "Há alguma observação sobre saúde, comportamento ou desenvolvimento que precise ser compartilhada com a coordenação ou família?"]}]'::jsonb);

-- Infantil 3 | 1º Semestre | 17 seções | 93 checklist | 53 texto
INSERT INTO qsi_templates (serie, semestre, titulo, subtitulo, sections)
VALUES ('Infantil 3', 1, 'Questionário de Sondagem — Infantil 3', 'Instrumento para levantamento do desenvolvimento da criança no início do ano letivo', '[{"title": "1. Identidade, Autonomia, Convivência e Regulação Emocional", "bncc": "BNCC: EI02EO01, EI02EO02, EI02EO03, EI02EO04 | Campos: O eu, o outro e o nós", "checklist": ["Responde ao próprio nome e reconhece-se em fotos e no espelho", "Reconhece seus pertences entre os dos colegas", "Brinca paralelamente próximo aos colegas, observando e imitando", "Expressa emoções básicas por choro, gestos, expressões faciais ou palavras", "Segue comandos simples dados pelo adulto (''senta'', ''vem'', ''guarda'')", "Aceita a permanência na escola após período de adaptação", "Aceita a rotina básica com apoio: lanche, roda, trocas, parque", "Procura o adulto quando precisa de ajuda ou conforto"], "prompts": ["Conte como foi o processo de adaptação desta criança. Como ela se relaciona com adultos e colegas?", "Como a criança expressa suas emoções no dia a dia? Há algo que chama atenção?", "Observações sobre identidade, autonomia, convivência e regulação emocional:"]}, {"title": "2. Coordenação Motora Ampla e Esquema Corporal", "bncc": "BNCC: EI02CG01, EI02CG02, EI02CG03 | Campos: Corpo, gestos e movimentos", "checklist": ["Anda e corre com coordenação ainda em desenvolvimento", "Pula com dificuldade, ainda sem simultaneidade dos dois pés", "Imita movimentos corporais simples: bater palmas, balançar, girar", "Sobe em móveis baixos e degraus com apoio", "Agacha-se e levanta-se com ou sem apoio", "Chuta bola quando posicionada à frente", "Identifica partes do corpo quando nomeadas pelo adulto", "Movimenta-se ao som de música"], "prompts": ["Há alguma particularidade no desenvolvimento motor amplo desta criança (inseguranças, avanços, apoio necessário)?", "Como a criança se movimenta em espaços abertos (parque, pátio)? Demonstra confiança?", "Observações sobre coordenação motora ampla e esquema corporal:"]}, {"title": "3. Coordenação Motora Fina e Manipulação", "bncc": "BNCC: EI02CG05 | Campos: Corpo, gestos e movimentos", "checklist": ["Segura lápis de forma imatura (preensão palmar predominante)", "Rasga papel com as mãos", "Manipula objetos grandes: blocos, bolas, potes", "Encaixa peças grandes em brinquedos de encaixe", "Empilha blocos (2-4 peças)", "Amassa e manipula massinha", "Folheia páginas de livros cartonados", "Cola materiais com ajuda"], "prompts": ["Como é a preensão ao segurar lápis ou giz? A criança demonstra dificuldades em atividades manuais?", "Quais atividades de manipulação mais despertam o interesse da criança?", "Observações sobre coordenação motora fina e manipulação:"]}, {"title": "4. Grafomotricidade, Traçado e Organização Espacial no Papel", "bncc": "BNCC: EI02TS01, EI02TS02 | Campos: Traços, sons, cores e formas", "checklist": ["Faz rabiscos sem controle de direção ou forma definida", "Não segue direção específica ao traçar", "Ocupa o papel de forma aleatória", "Faz traçados amplos em suportes grandes (lousa, chão)", "Explora diferentes riscantes: giz, canetão, tinta"], "prompts": ["Descreva como a criança organiza o espaço do papel ao rabiscar ou desenhar. Há direção ou intenção no traço?", "A criança demonstra interesse por atividades de traçado? Como reage?", "Observações sobre grafomotricidade e traçado:"]}, {"title": "5. Desenho, Pintura, Recorte e Colagem", "bncc": "BNCC: EI02TS01, EI02TS02, EI02TS03 | Campos: Traços, sons, cores e formas", "checklist": ["Desenha rabiscos sem forma definida", "Pinta sem controle, extrapolando limites amplamente", "Recorta com ajuda (adulto guia a tesoura)", "Explora tinta com as mãos e dedos", "Escolhe cores por preferência", "Cola materiais com ajuda do adulto", "Demonstra prazer em atividades de pintura e desenho"], "prompts": ["O que costuma aparecer nos rabiscos e produções visuais desta criança? Ela nomeia o que faz?", "Como a criança reage a materiais artísticos novos (tinta, cola, massa, sucata)?", "Observações sobre desenho, pintura, recorte e colagem:"]}, {"title": "6. Percepção Visual e Discriminação", "bncc": "BNCC: EI02TS02, EI02ET01 | Campos: Traços, sons, cores e formas; Espaços, tempos, quantidades, relações e transformações", "checklist": ["Reconhece figuras iguais com ajuda do adulto", "Identifica cores parcialmente (reconhece 1-2 cores)", "Diferencia grande e pequeno em situações concretas", "Encaixa formas em brinquedos de encaixe", "Observa imagens em livros e aponta elementos", "Monta quebra-cabeças de 2-3 peças"], "prompts": ["Como a criança se comporta em jogos de memória ou atividades de pareamento? Mantém atenção?", "Quais cores a criança já reconhece e nomeia? Quais formas?", "Observações sobre percepção visual e discriminação:"]}, {"title": "7. Atenção, Memória e Funções Executivas", "bncc": "BNCC: EI02EO04, EI02EF01 | Campos: O eu, o outro e o nós; Escuta, fala, pensamento e imaginação", "checklist": ["Mantém atenção por períodos muito curtos em atividades dirigidas", "Precisa de ajuda constante para manter-se na tarefa", "Segue comandos simples de uma etapa com apoio", "Necessita de redirecionamento frequente", "Lembra momentos da rotina imediata"], "prompts": ["Quais estratégias ajudam esta criança a manter o foco? Há momentos do dia em que a atenção é melhor ou pior?", "A criança consegue seguir instruções sem repetição? Descreva.", "Observações sobre atenção, memória e funções executivas:"]}, {"title": "8. Linguagem Oral, Compreensão e Comunicação", "bncc": "BNCC: EI02EF01, EI02EF02, EI02EF03 | Campos: Escuta, fala, pensamento e imaginação", "checklist": ["Fala palavras isoladas ou junta duas palavras", "Nomeia objetos e pessoas familiares", "Compreende comandos simples de uma etapa", "Aponta e nomeia figuras em livros", "Usa gestos e palavras para se comunicar", "Participa de canções com gestos e movimentos", "Demonstra atenção por breves momentos a histórias com imagens"], "prompts": ["Como você descreveria a comunicação oral desta criança? Ela se expressa por iniciativa própria?", "A criança demonstra interesse por histórias e livros? Como reage nos momentos de leitura?", "Observações sobre linguagem oral, compreensão e comunicação:"]}, {"title": "9. Consciência Fonológica e Análise Sonora", "bncc": "BNCC: EI02EF03, EI02EF04 | Campos: Escuta, fala, pensamento e imaginação", "checklist": ["Percebe rimas em cantigas e brincadeiras cantadas", "Repete sons e sílabas produzidos pelo adulto", "Participa de parlendas, cantigas e jogos sonoros com prazer", "Reage a sons do ambiente e os identifica", "Demonstra atenção a jogos com sons e repetições"], "prompts": ["Em atividades de rima ou jogos sonoros, como esta criança reage? Ela demonstra perceber os sons?", "A criança demonstra prazer em brincadeiras com sons e músicas?", "Observações sobre consciência fonológica e análise sonora:"]}, {"title": "10. Nome, Letras e Contato Inicial com a Escrita", "bncc": "BNCC: EI02EF03, EI02EF05 | Campos: Escuta, fala, pensamento e imaginação", "checklist": ["Reconhece o próprio nome com ajuda (crachá, foto, contexto)", "Observa letras e símbolos no ambiente sem identificá-los", "Demonstra curiosidade por materiais escritos (livros, cartazes, rótulos)", "Diferencia escrita de desenho de forma muito inicial"], "prompts": ["A criança reconhece seu nome escrito? Em quais contextos? Com ou sem apoio?", "A criança demonstra interesse por letras e palavras escritas no ambiente?", "Observações sobre nome, letras e contato com a escrita:"]}, {"title": "11. Escrita Emergente e Primeiras Hipóteses", "bncc": "BNCC: EI02EF05 | Campos: Escuta, fala, pensamento e imaginação", "checklist": ["Faz rabiscos como tentativa de escrita", "Mistura desenho e escrita sem diferenciação clara", "Imita o gesto de escrever observando adultos", "Atribui significado a rabiscos quando perguntada"], "prompts": ["Descreva como é a escrita espontânea desta criança: o que ela produz, como reage à proposta?", "A criança demonstra interesse pelo ato de escrever? Imita adultos?", "Observações sobre escrita emergente:"]}, {"title": "12. Numerais, Contagem e Quantificação", "bncc": "BNCC: EI02ET01, EI02ET03 | Campos: Espaços, tempos, quantidades, relações e transformações", "checklist": ["Recita números de forma aleatória ou parcialmente ordenada", "Reconhece poucos numerais visualmente (1, 2)", "Diferencia ''um'' e ''muitos'' em situações concretas", "Conta mecanicamente até 2-3 com apoio", "Separa 1 ou 2 objetos quando solicitado"], "prompts": ["Até qual número esta criança conta com segurança? Usa dedos ou objetos como apoio?", "A criança consegue associar quantidade ao numeral? Descreva.", "Observações sobre numerais, contagem e quantificação:"]}, {"title": "13. Formas, Geometria Inicial, Classificação e Padrões", "bncc": "BNCC: EI02ET01, EI02ET05 | Campos: Espaços, tempos, quantidades, relações e transformações", "checklist": ["Reconhece formas com ajuda em brinquedos de encaixe", "Classifica por cor em situações concretas e dirigidas", "Agrupa objetos iguais", "Diferencia grande e pequeno", "Encaixa formas em caixas de encaixe"], "prompts": ["Como a criança reage a atividades de classificação e padrões?", "Ela consegue agrupar objetos e explicar o critério usado?", "Observações sobre formas, classificação e padrões:"]}, {"title": "14. Noções Espaço-Temporais e Rotina", "bncc": "BNCC: EI02ET02 | Campos: Espaços, tempos, quantidades, relações e transformações", "checklist": ["Reconhece momentos da rotina básica: lanche, parque, saída", "Diferencia dia e noite em situações concretas", "Compreende ''agora'' e ''depois'' de forma inicial", "Coloca e tira objetos de recipientes (dentro/fora)", "Reconhece ''em cima'' e ''embaixo'' em contextos concretos"], "prompts": ["A criança demonstra compreender a rotina do dia? Ela antecipa o que vem a seguir?", "Como a criança usa noções espaciais no cotidiano?", "Observações sobre noções espaço-temporais e rotina:"]}, {"title": "15. Investigação, Curiosidade e Raciocínio", "bncc": "BNCC: EI02ET02, EI02ET04 | Campos: Espaços, tempos, quantidades, relações e transformações", "checklist": ["Explora objetos e materiais com curiosidade", "Observa mudanças no ambiente (chuva, vento, luz, sombra)", "Reage a estímulos novos com curiosidade ou estranhamento", "Coloca e tira objetos de recipientes, empilha e derruba", "Demonstra interesse por experiências sensoriais"], "prompts": ["A criança demonstra curiosidade e interesse por investigar? Dê um exemplo recente.", "Como a criança reage a experiências sensoriais e investigativas?", "Observações sobre investigação, curiosidade e raciocínio:"]}, {"title": "16. Expressão Artística, Musical, Corporal e Imaginação Simbólica", "bncc": "BNCC: EI02TS03, EI02CG03, EI02EF02 | Campos: Traços, sons, cores e formas; Corpo, gestos e movimentos; Escuta, fala, pensamento e imaginação", "checklist": ["Imita gestos do adulto em músicas e brincadeiras", "Participa de músicas e canções com movimentos", "Inicia brincadeira de faz de conta simples: finge dar comida, ninar, passear", "Explora instrumentos sonoros simples: chocalho, pandeirola, tambor", "Movimenta-se ao som de música", "Demonstra prazer em momentos de história, música e teatro"], "prompts": ["Como esta criança se engaja no faz de conta? Ela cria enredos e distribui papéis?", "Quais linguagens artísticas mais atraem esta criança (música, dança, teatro, artes visuais)?", "Observações sobre expressão artística, musical, corporal e imaginação simbólica:"]}, {"title": "Considerações Gerais e Síntese", "bncc": "", "checklist": [], "prompts": ["Quais são os pontos fortes mais marcantes desta criança neste semestre?", "Em quais áreas você observa maior necessidade de atenção ou estimulação?", "Há algo no contexto familiar ou nas interações sociais que influencia o desenvolvimento observado?", "Quais estratégias pedagógicas têm funcionado bem com esta criança?", "Há alguma observação sobre saúde, comportamento ou desenvolvimento que precise ser compartilhada com a coordenação ou família?"]}]'::jsonb);

-- Infantil 3 | 2º Semestre | 17 seções | 112 checklist | 53 texto
INSERT INTO qsi_templates (serie, semestre, titulo, subtitulo, sections)
VALUES ('Infantil 3', 2, 'Questionário de Sondagem — Infantil 3', 'Instrumento para levantamento do desenvolvimento da criança ao final do ano letivo', '[{"title": "1. Identidade, Autonomia, Convivência e Regulação Emocional", "bncc": "BNCC: EI02EO01, EI02EO02, EI02EO03, EI02EO04 | Campos: O eu, o outro e o nós", "checklist": ["Identifica seus pertences (mochila, garrafa, casaco) e os guarda com orientação", "Interage com colegas em brincadeiras cooperativas simples, não apenas paralelas", "Nomeia emoções básicas (alegria, tristeza, raiva, medo) em si e nos outros", "Segue combinados da turma com apoio verbal e visual", "Participa da rotina com crescente autonomia: lanche, roda, higiene, parque", "Aceita compartilhar brinquedos e materiais com mediação do adulto", "Espera a vez em situações simples (fila, jogos, fala) com apoio", "Procura o adulto para resolver conflitos e aceita a mediação proposta", "Tolera pequenas frustrações com ajuda do adulto"], "prompts": ["Conte como foi o processo de adaptação desta criança. Como ela se relaciona com adultos e colegas?", "Comparando com o início do ano, como evoluiu a convivência, a regulação emocional e a autonomia? Dê exemplos.", "Observações sobre identidade, autonomia, convivência e regulação emocional:"]}, {"title": "2. Coordenação Motora Ampla e Esquema Corporal", "bncc": "BNCC: EI02CG01, EI02CG02, EI02CG03 | Campos: Corpo, gestos e movimentos", "checklist": ["Corre com controle de direção e velocidade, parando sem cair", "Pula com os dois pés juntos simultaneamente", "Equilibra-se sobre superfícies estreitas ou elevadas com apoio", "Sobe e desce escadas com apoio, alternando ou não os pés", "Chuta bola para frente com direção aproximada", "Coordena movimentos amplos em circuitos e brincadeiras dirigidas", "Imita sequências de movimentos: levantar, abaixar, girar, pular", "Identifica partes do corpo quando nomeadas e começa a nomeá-las", "Movimenta-se ao som de música com coordenação crescente"], "prompts": ["Há alguma particularidade no desenvolvimento motor amplo desta criança (inseguranças, avanços, apoio necessário)?", "Como a criança se movimenta em espaços abertos (parque, pátio)? Demonstra confiança?", "Observações sobre coordenação motora ampla e esquema corporal:"]}, {"title": "3. Coordenação Motora Fina e Manipulação", "bncc": "BNCC: EI02CG05 | Campos: Corpo, gestos e movimentos", "checklist": ["Melhora a preensão do lápis, giz e pincel, em transição para preensão digital", "Usa pinça inicial para pegar objetos pequenos", "Manipula objetos pequenos com destreza crescente: miçangas, botões, peças de encaixe", "Encaixa peças em brinquedos de encaixe e quebra-cabeças simples (4-6 peças)", "Empilha blocos com estabilidade (5-8 peças)", "Amassa, enrola e modela massinha com intenção", "Rasga papel em pedaços menores e cola com ajuda", "Recorta com tesoura em movimentos simples (picotar, recortar linha reta com apoio)", "Abre e fecha potes, tampas e zíperes"], "prompts": ["Como é a preensão ao segurar lápis ou giz? A criança demonstra dificuldades em atividades manuais?", "Quais atividades de manipulação mais despertam o interesse da criança?", "Observações sobre coordenação motora fina e manipulação:"]}, {"title": "4. Grafomotricidade, Traçado e Organização Espacial no Papel", "bncc": "BNCC: EI02TS01, EI02TS02 | Campos: Traços, sons, cores e formas", "checklist": ["Faz traços simples com direção: verticais, horizontais, circulares", "Cobre pontilhados com ajuda, mantendo proximidade ao modelo", "Organiza melhor o espaço do papel, distribuindo traços de forma menos aleatória", "Faz traçados em suportes variados: lousa, chão, folhas grandes", "Tenta reproduzir formas simples (círculo, cruz) a partir de modelo", "Rabisca com intenção de desenho ou escrita, nomeando produções"], "prompts": ["Descreva como a criança organiza o espaço do papel ao rabiscar ou desenhar. Há direção ou intenção no traço?", "Comparando com o início do ano, como evoluiu o traçado? A criança já tenta reproduzir formas?", "Observações sobre grafomotricidade e traçado:"]}, {"title": "5. Desenho, Pintura, Recorte e Colagem", "bncc": "BNCC: EI02TS01, EI02TS02, EI02TS03 | Campos: Traços, sons, cores e formas", "checklist": ["Representa formas simples no desenho: círculos, linhas, figuras iniciais", "Nomeia o que desenhou quando perguntada", "Pinta com mais controle, preenchendo áreas maiores", "Recorta de forma simples: picotes e recortes livres com tesoura", "Explora tinta, pincel, esponja, dedos e outros instrumentos", "Reconhece e nomeia algumas cores básicas", "Cola materiais com ajuda, posicionando de forma mais intencional", "Demonstra prazer em atividades artísticas"], "prompts": ["O que costuma aparecer nos rabiscos e produções visuais desta criança? Ela nomeia o que faz?", "Como a criança reage a materiais artísticos novos (tinta, cola, massa, sucata)?", "Observações sobre desenho, pintura, recorte e colagem:"]}, {"title": "6. Percepção Visual e Discriminação", "bncc": "BNCC: EI02TS02, EI02ET01 | Campos: Traços, sons, cores e formas; Espaços, tempos, quantidades, relações e transformações", "checklist": ["Reconhece cores básicas (vermelho, azul, amarelo, verde) e as nomeia", "Pareia figuras iguais em jogos de memória e pareamento", "Identifica formas geométricas básicas: círculo, quadrado, triângulo", "Percebe semelhanças e diferenças entre objetos e figuras", "Monta quebra-cabeças simples de poucas peças (4-6)", "Encontra objetos ou imagens específicas em conjuntos visuais", "Observa detalhes em imagens e cenas simples"], "prompts": ["Como a criança se comporta em jogos de memória ou atividades de pareamento? Mantém atenção?", "Quais cores a criança já reconhece e nomeia? Quais formas?", "Observações sobre percepção visual e discriminação:"]}, {"title": "7. Atenção, Memória e Funções Executivas", "bncc": "BNCC: EI02EO04, EI02EF01 | Campos: O eu, o outro e o nós; Escuta, fala, pensamento e imaginação", "checklist": ["Mantém atenção por períodos maiores em atividades dirigidas (5-10 minutos)", "Segue instruções simples de uma etapa sem necessidade de repetição constante", "Lembra partes da rotina e antecipa o que vem a seguir", "Inicia atividades com menor necessidade de apoio para se organizar", "Retoma a tarefa após breve interrupção com apoio", "Controla impulsos em situações simples com apoio do adulto"], "prompts": ["Quais estratégias ajudam esta criança a manter o foco? Há momentos do dia em que a atenção é melhor ou pior?", "A criança consegue seguir instruções sem repetição? Descreva.", "Observações sobre atenção, memória e funções executivas:"]}, {"title": "8. Linguagem Oral, Compreensão e Comunicação", "bncc": "BNCC: EI02EF01, EI02EF02, EI02EF03 | Campos: Escuta, fala, pensamento e imaginação", "checklist": ["Fala frases simples compreensíveis na maior parte do tempo", "Responde perguntas diretas: ''quem?'', ''o quê?'', ''onde?''", "Relata pequenas ações e fatos do cotidiano", "Nomeia objetos, pessoas e ações do dia a dia com vocabulário crescente", "Compreende histórias curtas com apoio de imagens", "Participa de canções e repete refrões conhecidos", "Amplia vocabulário progressivamente", "Demonstra atenção a histórias lidas pelo adulto"], "prompts": ["Como você descreveria a comunicação oral desta criança? Ela se expressa por iniciativa própria?", "A criança demonstra interesse por histórias e livros? Como reage nos momentos de leitura?", "Observações sobre linguagem oral, compreensão e comunicação:"]}, {"title": "9. Consciência Fonológica e Análise Sonora", "bncc": "BNCC: EI02EF03, EI02EF04 | Campos: Escuta, fala, pensamento e imaginação", "checklist": ["Identifica rimas em cantigas, parlendas e poemas curtos", "Completa rimas e refrões conhecidos", "Segmenta sílabas de palavras simples batendo palmas com apoio", "Demonstra prazer em jogos sonoros, trava-línguas e repetições orais", "Percebe palavras que começam com sons parecidos em contextos lúdicos", "Repete sons e sílabas produzidos pelo adulto"], "prompts": ["Em atividades de rima ou jogos sonoros, como esta criança reage? Ela demonstra perceber os sons?", "A criança já consegue bater palmas separando sílabas? Completa rimas?", "Observações sobre consciência fonológica e análise sonora:"]}, {"title": "10. Nome, Letras e Contato Inicial com a Escrita", "bncc": "BNCC: EI02EF03, EI02EF05 | Campos: Escuta, fala, pensamento e imaginação", "checklist": ["Reconhece o próprio nome escrito entre outros nomes", "Identifica a letra inicial do próprio nome", "Associa o som inicial do nome à letra correspondente", "Observa letras no ambiente e demonstra curiosidade", "Diferencia letras de desenhos e números em fase inicial", "Tenta escrever o próprio nome com apoio de modelo"], "prompts": ["A criança reconhece seu nome escrito? Em quais contextos? Com ou sem apoio?", "A criança identifica a letra inicial do próprio nome? Associa ao som?", "Observações sobre nome, letras e contato com a escrita:"]}, {"title": "11. Escrita Emergente e Primeiras Hipóteses", "bncc": "BNCC: EI02EF05 | Campos: Escuta, fala, pensamento e imaginação", "checklist": ["Usa letras iniciais ou pseudoletras em tentativas de escrita", "Organiza melhor a escrita: distribui marcas no papel de forma mais intencional", "Diferencia desenho de escrita com maior clareza", "Tenta escrever o próprio nome com apoio de modelo", "Atribui significado às suas produções escritas (''aqui diz...'')", "Demonstra interesse em saber o que está escrito em textos do ambiente"], "prompts": ["Descreva como é a escrita espontânea desta criança: o que ela produz, como reage à proposta?", "A criança já diferencia desenho de escrita? Já usa letras ou pseudoletras?", "Observações sobre escrita emergente:"]}, {"title": "12. Numerais, Contagem e Quantificação", "bncc": "BNCC: EI02ET01, EI02ET03 | Campos: Espaços, tempos, quantidades, relações e transformações", "checklist": ["Conta até 5 com sequência oral estável", "Associa quantidade simples ao numeral correspondente (1-3)", "Reconhece numerais de 1 a 5 visualmente", "Compara ''mais'' e ''menos'' em coleções concretas pequenas", "Separa 1, 2 ou 3 objetos quando solicitado", "Conta pequenas coleções apontando para cada elemento (correspondência um a um iniciando)"], "prompts": ["Até qual número esta criança conta com segurança? Usa dedos ou objetos como apoio?", "A criança consegue associar quantidade ao numeral? Descreva.", "Observações sobre numerais, contagem e quantificação:"]}, {"title": "13. Formas, Geometria Inicial, Classificação e Padrões", "bncc": "BNCC: EI02ET01, EI02ET05 | Campos: Espaços, tempos, quantidades, relações e transformações", "checklist": ["Identifica formas geométricas básicas: círculo, quadrado, triângulo", "Nomeia formas com apoio", "Organiza sequências simples de 2 elementos (AB, AB)", "Classifica objetos por um critério: cor, forma ou tamanho", "Ordena poucos elementos por tamanho com apoio", "Percebe semelhanças e diferenças entre objetos e figuras"], "prompts": ["Como a criança reage a atividades de classificação e padrões?", "Ela consegue agrupar objetos e explicar o critério usado?", "Observações sobre formas, classificação e padrões:"]}, {"title": "14. Noções Espaço-Temporais e Rotina", "bncc": "BNCC: EI02ET02 | Campos: Espaços, tempos, quantidades, relações e transformações", "checklist": ["Reconhece a sequência da rotina do dia e antecipa etapas", "Participa do calendário com ajuda do adulto", "Compreende antes/depois em situações concretas", "Identifica dia/noite em situações do cotidiano", "Compreende referências espaciais simples: dentro/fora, em cima/embaixo, perto/longe", "Localiza objetos e pessoas por referências espaciais básicas"], "prompts": ["A criança demonstra compreender a rotina do dia? Ela antecipa o que vem a seguir?", "Como a criança usa noções espaciais no cotidiano?", "Observações sobre noções espaço-temporais e rotina:"]}, {"title": "15. Investigação, Curiosidade e Raciocínio", "bncc": "BNCC: EI02ET02, EI02ET04 | Campos: Espaços, tempos, quantidades, relações e transformações", "checklist": ["Compara objetos por características concretas: cor, tamanho, forma, textura", "Testa ideias simples em situações de exploração: ''o que acontece se...''", "Observa mudanças e transformações em materiais e fenômenos simples", "Faz perguntas sobre o que vê ou percebe", "Agrupa objetos e reconhece o que está faltando em conjuntos simples", "Acompanha investigações orientadas pelo adulto com curiosidade"], "prompts": ["A criança demonstra curiosidade e interesse por investigar? Dê um exemplo recente.", "Como a criança reage a experiências sensoriais e investigativas?", "Observações sobre investigação, curiosidade e raciocínio:"]}, {"title": "16. Expressão Artística, Musical, Corporal e Imaginação Simbólica", "bncc": "BNCC: EI02TS03, EI02CG03, EI02EF02 | Campos: Traços, sons, cores e formas; Corpo, gestos e movimentos; Escuta, fala, pensamento e imaginação", "checklist": ["Acompanha ritmo de músicas com palmas, balanço ou movimentos corporais", "Brinca simbolicamente: faz de conta, atribui papéis, cria situações imaginárias", "Expressa ideias e sentimentos por meio de música, desenho, dramatização ou movimento", "Participa de canções, parlendas e jogos musicais com gestos e letras", "Explora instrumentos musicais simples com intenção", "Dramatiza situações do cotidiano em brincadeiras", "Usa materiais diversos em produções artísticas com prazer e iniciativa", "Observa e comenta produções próprias e dos colegas"], "prompts": ["Como esta criança se engaja no faz de conta? Ela cria enredos e distribui papéis?", "Quais linguagens artísticas mais atraem esta criança (música, dança, teatro, artes visuais)?", "Observações sobre expressão artística, musical, corporal e imaginação simbólica:"]}, {"title": "Considerações Gerais e Síntese", "bncc": "", "checklist": [], "prompts": ["Quais são os pontos fortes mais marcantes desta criança neste semestre?", "Em quais áreas você observa maior necessidade de atenção ou estimulação?", "