VALUES ('Infantil 4', 1, 'Questionário de Sondagem — Infantil 4', 'Instrumento para levantamento do desenvolvimento da criança no início do ano letivo', '[{"title": "1. Identidade, Autonomia, Convivência e Regulação Emocional", "bncc": "BNCC: EI02EO01, EI02EO02, EI02EO03, EI02EO04, EI02EO05 | Campos: O eu, o outro e o nós", "checklist": ["Diz o próprio nome completo e reconhece dados pessoais básicos", "Reconhece pertences e os guarda com orientação", "Interage com colegas com mediação do adulto", "Segue combinados da turma com apoio visual e verbal", "Reconhece emoções básicas: alegria, tristeza, raiva, medo", "Expressa desejos e incômodos verbalmente", "Aceita compartilhar materiais com mediação", "Participa da rotina com apoio"], "prompts": ["Conte como foi o processo de adaptação. Como a criança se relaciona com adultos e colegas?", "Descreva como esta criança lida com situações de frustração ou conflito. Há estratégias que funcionam?", "Observações sobre autonomia, convivência e regulação emocional (inclua alimentação, higiene):"]}, {"title": "2. Coordenação Motora Ampla e Esquema Corporal", "bncc": "BNCC: EI02CG01, EI02CG02, EI02CG03, EI02CG04 | Campos: Corpo, gestos e movimentos", "checklist": ["Corre com coordenação básica", "Pula com os dois pés juntos", "Imita movimentos e posições corporais em brincadeiras", "Sobe escadas com apoio", "Chuta bola para frente", "Reconhece partes do corpo quando nomeadas", "Movimenta-se ao som de música"], "prompts": ["Há particularidades no desenvolvimento motor amplo (inseguranças, avanços, apoio necessário)?", "Como a criança se movimenta em espaços abertos? Demonstra confiança?", "Observações sobre coordenação motora ampla e esquema corporal:"]}, {"title": "3. Coordenação Motora Fina e Manipulação", "bncc": "BNCC: EI02CG05 | Campos: Corpo, gestos e movimentos", "checklist": ["Segura lápis com preensão palmar ou digital imatura", "Rasga papel com as mãos", "Manipula massinha amassando e enrolando", "Encaixa peças em brinq