INSERT INTO qsi_templates (serie, semestre, titulo, subtitulo, sections)
VALUES ('Infantil 4', 2, 'Questionário de Sondagem — Infantil 4', 'Instrumento para levantamento do desenvolvimento da criança ao final do ano letivo', '[{"title": "1. Identidade, Autonomia, Convivência e Regulação Emocional", "bncc": "BNCC: EI02EO01, EI02EO02, EI02EO03, EI02EO04, EI02EO05 | Campos: O eu, o outro e o nós", "checklist": ["Reconhece o próprio nome escrito e o diferencia de nomes semelhantes", "Interage em grupo, participando de brincadeiras cooperativas e projetos coletivos", "Espera a vez em jogos, conversas e uso de materiais com maior autocontrole", "Nomeia emoções básicas em si e nos outros com vocabulário emocional crescente", "Demonstra empatia: consola colegas, percebe quando alguém está triste ou precisando de ajuda", "Segue combinados da turma com consistência, lembrando-se deles em situações novas", "Resolve conflitos simples tentando dialogar antes de recorrer ao adulto", "Realiza a rotina com crescente autonomia: lanche, higiene, organização, fila", "Tolera frustrações com equilíbrio crescente"], "prompts": ["Conte como foi o processo de adaptação. Como a criança se relaciona com adultos e colegas?", "Comparando com o início do ano, como evoluiu a autonomia, a empatia e a convivência? Dê exemplos.", "Observações sobre autonomia, convivência e regulação emocional (inclua alimentação, higiene):"]}, {"title": "2. Coordenação Motora Ampla e Esquema Corporal", "bncc": "BNCC: EI02CG01, EI02CG02, EI02CG03, EI02CG04 | Campos: Corpo, gestos e movimentos", "checklist": ["Corre com controle de direção e velocidade, parando com equilíbrio", "Salta obstáculos de alturas variadas com segurança", "Equilibra-se sobre superfícies estreitas ou elevadas com maior autonomia", "Coordena movimentos amplos em circuitos, danças e brincadeiras dirigidas", "Sobe e desce escadas alternando os pés", "Chuta e arremessa bola com direção e força intencional", "Reconhece e nomeia partes do corpo, incluindo articulações", "Reproduz sequências de movimentos com precisão crescente", "Demonstra preferência lateral (mão, pé) com consistência"], "prompts": ["Há particularidades no desenvolvimento motor amplo (inseguranças, avanços, apoio necessário)?", "Comparando com o início do ano, quais conquistas motoras se destacam?", "Observações sobre coordenação motora ampla e esquema corporal:"]}, {"title": "3. Coordenação Motora Fina e Manipulação", "bncc": "BNCC: EI02CG05 | Campos: Corpo, gestos e movimentos", "checklist": ["Melhora a preensão do lápis, em transição para preensão trípode", "Usa pinça com destreza para pegar objetos pequenos e manipular materiais", "Recorta com tesoura em linhas retas e curvas simples com ajuda", "Encaixa peças pequenas, rosqueia e monta jogos com precisão crescente", "Modela massinha com formas intencionais", "Rasga papel em tiras controladas e cola com quantidade adequada", "Dobra papel seguindo marcas simples", "Abre e fecha potes, tampas, zíperes e presilhas com autonomia crescente", "Permanece em atividade de mesa por períodos progressivos"], "prompts": ["Como é a preensão ao segurar lápis ou pincel? Há dificuldades específicas?", "Quais atividades de manipulação mais despertam interesse?", "Observações sobre coordenação motora fina e manipulação:"]}, {"title": "4. Grafomotricidade, Traçado e Organização Espacial no Papel", "bncc": "BNCC: EI02TS01, EI02TS02 | Campos: Traços, sons, cores e formas", "checklist": ["Controla o traçado com maior precisão: linhas retas, curvas, onduladas", "Copia formas simples a partir de modelo: círculo, quadrado, cruz, triângulo", "Organiza o espaço do papel de forma mais planejada, distribuindo elementos", "Cobre pontilhados e liga pontos com controle do traço", "Mantém direção do traço com maior estabilidade (esquerda-direita)", "Tenta reproduzir letras e numerais com traçado próprio", "Respeita margens e limites visuais com menor necessidade de apoio"], "prompts": ["Descreva como a criança organiza o espaço do papel ao desenhar ou tentar escrever.", "Comparando com o início do ano, como evoluiu o controle do traço e a cópia de formas?", "Observações sobre grafomotricidade e traçado:"]}, {"title": "5. Desenho, Pintura, Recorte, Colagem e Composição Visual", "bncc": "BNCC: EI02TS01, EI02TS02, EI02TS03 | Campos: Traços, sons, cores e formas", "checklist": ["Desenha com intenção representativa: figuras humanas, objetos, cenas simples", "Nomeia e explica o que desenhou com clareza", "Pinta com controle crescente, preenchendo áreas e respeitando contornos", "Reconhece, nomeia e escolhe cores com intenção", "Recorta formas simples e cola com posicionamento mais intencional", "Explora tinta, pincel, rolinho e outros instrumentos com controle", "Participa de composições coletivas e individuais com criatividade"], "prompts": ["O que costuma aparecer nos desenhos desta criança? Ela consegue explicar o que desenhou?", "Como a criança reage a materiais artísticos novos?", "Observações sobre desenho, pintura, recorte, colagem e composição visual:"]}, {"title": "6. Percepção Visual e Discriminação", "bncc": "BNCC: EI02TS02, EI02ET01 | Campos: Traços, sons, cores e formas; Espaços, tempos, quantidades, relações e transformações", "checklist": ["Discrimina detalhes sutis em figuras e imagens", "Completa padrões visuais simples em sequências (AB, ABC)", "Encontra pares em jogos de memória com número crescente de peças", "Identifica e nomeia cores, incluindo secundárias", "Monta quebra-cabeças de 10-15 peças", "Reconhece letras e numerais familiares visualmente", "Observa modelos e os reproduz com fidelidade crescente"], "prompts": ["Como a criança se comporta em jogos de memória e atividades de discriminação visual?", "A criança consegue completar padrões visuais? Reproduzir modelos? Descreva.", "Observações sobre percepção visual e discriminação:"]}, {"title": "7. Atenção, Memória e Funções Executivas", "bncc": "BNCC: EI02EO04, EI02EF01 | Campos: O eu, o outro e o nós; Escuta, fala, pensamento e imaginação", "checklist": ["Mantém atenção ampliada em atividades dirigidas (10-15 minutos)", "Segue instruções de duas etapas com compreensão", "Lembra combinados e regras da turma sem lembrete constante", "Recorda acontecimentos e aprendizagens recentes", "Organiza materiais e inicia atividades com maior autonomia", "Transita entre tarefas com flexibilidade crescente", "Demonstra controle inibitório crescente: espera, pensa antes de agir"], "prompts": ["Quais estratégias ajudam esta criança a manter o foco? Há momentos melhores ou piores?", "Comparando com o início do ano, como evoluiu a atenção e a autorregulação?", "Observações sobre atenção, memória e funções executivas:"]}, {"title": "8. Linguagem Oral, Compreensão, Narrativa e Comunicação", "bncc": "BNCC: EI02EF01, EI02EF02, EI02EF03 | Campos: Escuta, fala, pensamento e imaginação", "checklist": ["Relata fatos, vivências e sequências de acontecimentos com organização temporal", "Reconta histórias com sequência lógica, com ou sem apoio de imagens", "Responde perguntas elaboradas: ''por quê?'', ''como?'', além de ''quem?'', ''o quê?'', ''onde?''", "Fala frases completas com conectivos (porque, então, depois)", "Nomeia objetos, ações e situações com vocabulário ampliado", "Participa de diálogos respeitando turnos de fala", "Amplia vocabulário incorporando palavras novas de histórias e conversas", "Argumenta e justifica opiniões em situações do cotidiano"], "prompts": ["Como você descreveria a comunicação oral desta criança? Ela se expressa por iniciativa própria?", "Há algo no repertório de linguagem que chama atenção (trocas fonológicas, vocabulário, fluência)?", "Observações sobre linguagem oral, compreensão, narrativa e comunicação:"]}, {"title": "9. Consciência Fonológica e Análise Sonora da Fala", "bncc": "BNCC: EI02EF03, EI02EF04 | Campos: Escuta, fala, pensamento e imaginação", "checklist": ["Identifica e produz rimas em cantigas, parlendas e jogos orais", "Segmenta sílabas de palavras batendo palmas com autonomia crescente", "Identifica sílaba ou som inicial de palavras familiares", "Compara palavras que começam com sons parecidos", "Demonstra prazer em trava-línguas, jogos sonoros e brincadeiras fonológicas", "Percebe palavras grandes e pequenas em brincadeiras orais"], "prompts": ["Em atividades de rima ou jogos sonoros, como a criança reage? Ela percebe os sons?", "A criança já segmenta sílabas e identifica sons iniciais com autonomia?", "Observações sobre consciência fonológica e análise sonora:"]}, {"title": "10. Conhecimento do Nome, Letras e Relação Letra/Som", "bncc": "BNCC: EI02EF03, EI02EF05 | Campos: Escuta, fala, pensamento e imaginação", "checklist": ["Nomeia letras do próprio nome e de palavras frequentes", "Associa o som de letras conhecidas à letra correspondente", "Reconhece o próprio nome escrito com segurança, diferenciando de semelhantes", "Identifica letras do alfabeto além das do próprio nome", "Diferencia letra de número, desenho e símbolo com clareza", "Demonstra interesse por palavras escritas no ambiente e tenta identificá-las", "Escreve o próprio nome de memória ou com apoio parcial"], "prompts": ["Quais letras esta criança reconhece e nomeia com segurança?", "A criança já escreve o próprio nome? De memória ou com modelo? Descreva.", "Observações sobre nome, letras e relação letra/som:"]}, {"title": "11. Escrita Emergente e Evolução das Hipóteses de Escrita", "bncc": "BNCC: EI02EF05 | Campos: Escuta, fala, pensamento e imaginação", "checklist": ["Usa letras convencionais em tentativas de escrita", "Evolui na hipótese de escrita: demonstra transição de rabiscos para uso de letras", "Diferencia claramente desenho de escrita", "Tenta escrever palavras além do próprio nome", "Começa a estabelecer relação entre partes sonoras e partes gráficas", "Demonstra interesse em saber o que está escrito", "Atribui significado às produções escritas"], "prompts": ["Descreva a escrita espontânea desta criança: o que ela produz, como reage à proposta?", "Comparando com o início do ano, como evoluiu a hipótese de escrita? Usa letras? Relaciona som e letra?", "Observações sobre escrita emergente e hipóteses de escrita:"]}, {"title": "12. Numerais, Contagem e Quantificação", "bncc": "BNCC: EI02ET01, EI02ET03 | Campos: Espaços, tempos, quantidades, relações e transformações", "checklist": ["Conta até 10 com sequência oral estável", "Associa quantidade ao numeral correspondente (1-5 com segurança)", "Reconhece numerais de 1 a 10 visualmente", "Conta coleções com correspondência biunívoca (um a um)", "Responde ''quantos?'' após contar, demonstrando cardinalidade", "Compara ''mais'', ''menos'' e ''igual'' em coleções concretas", "Separa quantidades solicitadas até 5 com autonomia", "Resolve situações-problema simples de juntar e tirar com material concreto"], "prompts": ["Até qual número a criança conta com segurança? Usa dedos ou objetos como apoio?", "A criança resolve situações de juntar e tirar? Dê um exemplo de raciocínio.", "Observações sobre numerais, contagem e quantificação:"]}, {"title": "13. Formas, Geometria Inicial, Classificação e Padrões", "bncc": "BNCC: EI02ET01, EI02ET05 | Campos: Espaços, tempos, quantidades, relações e transformações", "checklist": ["Nomeia formas geométricas: círculo, quadrado, triângulo, retângulo", "Completa padrões visuais e concretos (AB, ABC) com autonomia crescente", "Classifica por dois critérios simultâneos: cor e forma, cor e tamanho", "Ordena elementos por tamanho com autonomia crescente", "Percebe simetria em objetos e figuras simples", "Explica o critério de agrupamento quando perguntada"], "prompts": ["Como a criança reage a atividades de classificação e padrões?", "Ela consegue explicar por que agrupou objetos de determinada maneira?", "Observações sobre formas, classificação e padrões:"]}, {"title": "14. Noções Espaço-Temporais, Calendário e Rotina", "bncc": "BNCC: EI02ET02 | Campos: Espaços, tempos, quantidades, relações e transformações", "checklist": ["Reconhece e nomeia os dias da semana na sequência com apoio", "Compreende sequência temporal: antes/depois, ontem/hoje/amanhã", "Participa do calendário com compreensão crescente", "Antecipa etapas da rotina e descreve a sequência do dia", "Utiliza referências espaciais com precisão: dentro/fora, em cima/embaixo, perto/longe, frente/atrás", "Descreve posições e trajetórias usando linguagem espacial"], "prompts": ["A criança demonstra compreender a rotina? Ela antecipa o que vem a seguir?", "Como a criança usa noções espaciais e temporais no cotidiano?", "Observações sobre noções espaço-temporais e rotina:"]}, {"title": "15. Investigação, Curiosidade e Raciocínio", "bncc": "BNCC: EI02ET02, EI02ET04 | Campos: Espaços, tempos, quantidades, relações e transformações", "checklist": ["Compara objetos por múltiplas características: cor, tamanho, forma, textura, peso", "Testa ideias e formula hipóteses simples: ''acho que vai...'', ''e se...''", "Observa transformações em materiais e fenômenos com atenção", "Faz perguntas elaboradas sobre o que observa", "Registra observações por meio de desenhos", "Recorda informações de experiências anteriores e as aplica em situações novas"], "prompts": ["A criança demonstra curiosidade investigativa? Dê um exemplo recente.", "A criança formula hipóteses e testa ideias? Descreva.", "Observações sobre investigação, curiosidade e raciocínio:"]}, {"title": "16. Expressão Artística, Musical, Corporal e Imaginação Simbólica", "bncc": "BNCC: EI02TS03, EI02CG03, EI02EF02 | Campos: Traços, sons, cores e formas; Corpo, gestos e movimentos; Escuta, fala, pensamento e imaginação", "checklist": ["Acompanha ritmo de músicas com movimentos coordenados", "Dramatiza situações do cotidiano e cria enredos elaborados no faz de conta", "Expressa ideias e sentimentos por meio de música, desenho, dramatização ou movimento", "Atribui papéis e usa objetos de forma simbólica e criativa", "Participa de canções e jogos musicais com memória das letras e gestos", "Explora instrumentos musicais com intenção", "Usa materiais diversos em produções artísticas com iniciativa", "Aprecia e comenta produções próprias e dos colegas"], "prompts": ["Como esta criança se engaja no faz de conta? Ela cria enredos, distribui papéis, usa objetos de forma imaginativa?", "Quais linguagens artísticas mais atraem esta criança?", "Observações sobre expressão artística, musical, corporal e imaginação simbólica:"]}, {"title": "Considerações Gerais e Síntese", "bncc": "", "checklist": [], "prompts": ["Quais são os pontos fortes mais marcantes desta criança neste semestre? O que faz com autonomia e prazer?", "Em quais áreas você observa maior necessidade de atenção, suporte ou estimulação?", "Há algo no contexto familiar, nas interações sociais ou na história desta criança que influencia o desenvolvimento observado?", "Quais estratégias pedagógicas você já identificou que funcionam bem com esta criança?", "Há alguma observação sobre saúde, comportamento ou desenvolvimento que precise ser compartilhada com a coordenação ou família?"]}]'::jsonb);

-- Infantil 5 | 1º Semestre | 17 seções | 136 checklist | 33 texto
INSERT INTO qsi_templates (serie, semestre, titulo, subtitulo, sections)
VALUES ('Infantil 5', 1, 'Questionário de Sondagem — Infantil 5', 'Instrumento para levantamento do desenvolvimento da criança no início do ano letivo', '[{"title": "1. Identidade, Autonomia, Convivência e Regulação Emocional", "bncc": "BNCC: EI03EO01, EI03EO02, EI03EO03, EI03EO04, EI03EO06 | Campos: O eu, o outro e o nós; Corpo, gestos e movimentos", "checklist": ["Diz o próprio nome e reconhece sua foto, crachá ou identificação entre outras", "Identifica colegas e adultos de referência pelo nome", "Reconhece seus pertences e sabe guardar mochila, garrafa, casaco e materiais com orientação", "Participa de rodas de conversa com mediação, permanecendo no grupo por tempo progressivo", "Espera a sua vez em jogos, fala ou uso de materiais por curtos períodos", "Aceita compartilhar brinquedos e materiais quando lembrada pelo adulto", "Compreende combinados simples da turma e os segue com apoio visual e verbal", "Reconhece emoções básicas em si e nos outros: alegria, tristeza, raiva, medo", "Verbaliza desejos e incômodos simples em vez de usar apenas choro, recusa ou impulsividade", "Procura o adulto para resolver conflitos e aceita a mediação proposta", "Tolera pequenas frustrações com ajuda e retoma a atividade após acolhimento", "Realiza parte da rotina com apoio: sentar para lanche, guardar materiais, organizar fila, ir ao banheiro, lavar as mãos", "Aceita mudanças simples na rotina quando avisada e acompanhada pelo adulto"], "prompts": ["Descreva como esta criança lida com situações de frustração ou conflito com colegas. Há alguma estratégia que funciona bem com ela?", "Observações sobre autonomia, convivência e regulação emocional: (neste espaço fale sobre alimentação, sono, higiene…"]}, {"title": "2. Coordenação Motora Ampla, Esquema Corporal e Lateralidade", "bncc": "BNCC: EI03CG01, EI03CG02, EI03CG03, EI03CG05, EI03ET04 | Campos: Corpo, gestos e movimentos; Espaços, tempos, quantidades, relações e transformações", "checklist": ["Corre com coordenação básica em linha reta e muda de direção com ajuda", "Para após correr com controle inicial, sem cair com frequência", "Pula com os dois pés simultaneamente", "Salta pequenos obstáculos e desce pequenos desníveis", "Sobe escadas alternando os pés; desce com alguma insegurança ou necessidade de apoio eventual", "Anda em linha, trilha ou circuito simples com referência visual", "Chuta bola para frente e arremessa bola grande com direção aproximada", "Tenta receber bola grande com o corpo ou braços", "Imita movimentos, posições e gestos em brincadeiras dirigidas", "Reconhece e nomeia partes principais do corpo", "Compreende comandos motores simples: levantar, sentar, girar, abaixar, pular, correr, parar", "Inicia noções de direita/esquerda no próprio corpo em situações muito concretas"], "prompts": ["Há alguma particularidade no desenvolvimento motor desta criança que você considera importante registrar (ex.: inseguranças, avanços, necessidade de apoio específico)?", "Observações sobre movimento, esquema corporal e lateralidade:"]}, {"title": "3. Coordenação Motora Fina, Manipulação e Autonomia Manual", "bncc": "BNCC: EI03CG05, EI03TS02, EI03TS03 | Campos: Corpo, gestos e movimentos; Traços, sons, cores e formas", "checklist": ["Segura lápis, giz, pincel ou canetão de forma funcional, ainda que a preensão não esteja madura", "Abre e fecha potes, tampas, zíperes, caixas e presilhas com algum apoio", "Encaixa peças pequenas, rosqueia, monta e desmonta jogos simples", "Usa movimento de pinça para pegar objetos pequenos em atividades dirigidas", "Amassa, enrola, aperta e achata massinha com intenção", "Rasga papel, separa pequenos pedaços e cola com ajuda", "Dobra papel com mediação e segue marcas simples", "Passa cola em quantidades ainda irregulares, necessitando orientação", "Tenta usar tesoura abrindo e fechando com coordenação inicial", "Permanece em atividade de mesa por período curto, com necessidade de pausas e redirecionamento"], "prompts": ["Como é a preensão desta criança ao segurar lápis ou pincel? Ela demonstra dificuldades específicas em atividades manuais?", "Observações sobre coordenação fina e manipulação:"]}, {"title": "4. Grafomotricidade, Traçado e Organização Espacial no Papel", "bncc": "BNCC: EI03CG05, EI03TS02, EI03EF09 | Campos: Corpo, gestos e movimentos; Traços, sons, cores e formas; Escuta, fala, pensamento e imaginação", "checklist": ["Faz traços verticais, horizontais, inclinados, curvos e ondulados", "Cobre pontilhados simples e liga pontos próximos", "Faz traçados amplos em folhas grandes, lousa, chão ou superfícies variadas", "Rabisca com intenção de desenho ou escrita, ainda com organização espacial limitada", "Tenta copiar formas simples a partir de modelo", "Ocupa o espaço do papel de forma ainda pouco planejada (muito dispersa ou muito concentrada)", "Mantém direção do traço de modo ainda instável", "Necessita de apoio para respeitar margens, limites ou alinhamentos visuais"], "prompts": ["Descreva como a criança organiza o espaço do papel ao desenhar ou tentar escrever. Há preferência por área específica da folha?", "Observações sobre grafomotricidade e traçado:"]}, {"title": "5. Desenho, Pintura, Recorte, Colagem e Composição Visual", "bncc": "BNCC: EI03TS01, EI03TS02, EI03TS03, EI03CG05 | Campos: Traços, sons, cores e formas; Corpo, gestos e movimentos", "checklist": ["Desenha espontaneamente e nomeia o que produziu", "Representa pessoas, objetos ou cenas com poucos elementos e traçados iniciais", "Diferencia desenho de escrita e usa desenho para comunicar ideias", "Explora tinta, pincel, rolinho, esponja, dedos e outros instrumentos", "Reconhece e nomeia algumas cores e escolhe cores por preferência", "Pinta áreas amplas, ainda extrapolando limites com frequência", "Segura a tesoura com ajuda, abre e fecha o instrumento e realiza cortes livres ou picotes", "Cola figuras ou papéis com mediação, posicionando elementos ainda de modo mais aleatório", "Participa de composições simples com recorte, colagem, desenho e sucata"], "prompts": ["O que costuma aparecer nos desenhos espontâneos desta criança? Ela consegue explicar o que desenhou?", "Observações sobre expressão visual e produção artística:"]}, {"title": "6. Percepção Visual, Discriminação, Memória Visual e Organização Perceptiva", "bncc": "BNCC: EI03TS02, EI03ET01, EI03ET05 | Campos: Traços, sons, cores e formas; Espaços, tempos, quantidades, relações e transformações", "checklist": ["Reconhece igual e diferente em figuras simples", "Encontra pares iguais em jogos de memória e pareamento", "Identifica cores básicas e formas simples", "Percebe alguns detalhes em imagens, cenas ou objetos", "Monta quebra-cabeças simples com poucas peças", "Acompanha sequências visuais simples com ajuda", "Reconhece letras e números muito familiares de forma inicial", "Observa modelos para copiar, ainda com dificuldade de manter correspondência visual"], "prompts": ["Como a criança se comporta em jogos de memória ou atividades de pareamento? Ela consegue manter atenção durante a atividade?", "Observações sobre percepção e discriminação visual:"]}, {"title": "7. Atenção, Memória e Funções Executivas", "bncc": "BNCC: EI03EO02, EI03EO03, EI03EF01, EI03EF07, EI03ET04 | Campos: O eu, o outro e o nós; Escuta, fala, pensamento e imaginação; Espaços, tempos, quantidades, relações e transformações", "checklist": ["Mantém atenção por curtos períodos em atividades dirigidas", "Precisa de redirecionamentos frequentes para retomar a tarefa", "Segue instruções de uma etapa e compreende parte de instruções de duas etapas com apoio", "Lembra combinados e regras simples quando relembrada pelo adulto", "Recorda partes da rotina e acontecimentos muito recentes", "Inicia atividades com ajuda para organizar materiais e entender o que fazer", "Muda de uma tarefa para outra com alguma dificuldade, sobretudo em situações de interrupção", "Controla impulsos apenas com apoio mais constante", "Interrompe colegas ou age antes de ouvir toda a orientação em várias situações"], "prompts": ["Quais estratégias você percebe que ajudam esta criança a manter o foco? Há momentos do dia em que a atenção é notavelmente melhor ou pior?", "Observações sobre atenção, memória e autorregulação:"]}, {"title": "8. Linguagem Oral, Compreensão, Narrativa e Comunicação", "bncc": "BNCC: EI03EF01, EI03EF03, EI03EF04, EI03EF06, EI03EF07, EI03EO04 | Campos: Escuta, fala, pensamento e imaginação; O eu, o outro e o nós", "checklist": ["Fala frases completas e compreensíveis na maior parte do tempo", "Nomeia objetos, pessoas, ações e situações do cotidiano", "Responde perguntas diretas como ''quem?'', ''o quê?'' e ''onde?''", "Compreende histórias curtas e identifica personagens principais", "Relata fatos simples ou vivências muito próximas do cotidiano", "Participa de diálogo com mediação, respeitando turnos de fala por curtos momentos", "Amplia vocabulário gradualmente ao ouvir histórias, conversas e cantigas", "Reconta trechos simples de histórias com apoio de imagens"], "prompts": ["Como você descreveria a comunicação oral desta criança? Ela costuma se expressar por iniciativa própria? Há algo no repertório de linguagem que chama atenção?", "Observações sobre linguagem oral e comunicação:"]}, {"title": "9. Consciência Fonológica e Análise Sonora da Fala", "bncc": "BNCC: EI03EF02, EI03EF03, EI03EF08, EI03EF09 | Campo: Escuta, fala, pensamento e imaginação", "checklist": ["Percebe rimas em cantigas, parlendas e poemas curtos", "Repete rimas e refrões conhecidos", "Percebe palavras grandes e pequenas em brincadeiras orais", "Bate palmas para palavras ou sílabas com apoio do adulto", "Identifica sílaba ou som inicial de palavras muito familiares quando apoiada por pistas", "Compara palavras que começam de forma parecida em contextos lúdicos", "Demonstra prazer em jogos sonoros, trava-línguas, cantigas e repetições orais"], "prompts": ["Em atividades de rima ou jogos sonoros, como esta criança reage? Ela demonstra perceber os sons das palavras ou ainda não apresenta essa consciência de forma consistente?", "Observações sobre consciência fonológica:"]}, {"title": "10. Conhecimento do Nome, Alfabeto e Relação Letra/Som", "bncc": "BNCC: EI03EF01, EI03EF03, EI03EF08, EI03EF09, EI03EO04 | Campos: Escuta, fala, pensamento e imaginação; O eu, o outro e o nós", "checklist": ["Reconhece o próprio nome entre outros", "Encontra seu crachá ou identificação em contextos de chamada, materiais ou rotina", "Identifica a letra inicial do próprio nome", "Reconhece algumas letras do alfabeto, principalmente as do próprio nome e de palavras muito frequentes", "Diferencia letra de número, desenho e rabisco", "Nomeia algumas letras", "Percebe que palavras diferentes começam com letras diferentes, ainda sem estabilidade", "Identifica visualmente algumas vogais e algumas consoantes familiares"], "prompts": ["Quais letras esta criança já reconhece com mais segurança? Ela demonstra interesse por palavras escritas no ambiente da sala?", "Ela sabe escrever (de memória ou com apoio) alguma letra ou o próprio nome? Descreva o que foi observado:", "Observações sobre conhecimento do alfabeto e relação letra/som:"]}, {"title": "11. Escrita Emergente e Evolução das Hipóteses de Escrita", "bncc": "BNCC: EI03EF01, EI03EF06, EI03EF08, EI03EF09, EI03TS02 | Campos: Escuta, fala, pensamento e imaginação; Traços, sons, cores e formas", "checklist": ["Reconhece que a escrita tem função social e serve para comunicar algo", "Diferencia desenho de escrita", "Faz escrita espontânea usando rabiscos, pseudoletras ou letras aleatórias com intenção comunicativa", "Tenta escrever o próprio nome com apoio de modelo ou memória parcial", "Utiliza letras do próprio nome em outras escritas", "Ainda não mantém relação estável entre quantidade de letras e partes sonoras da fala", "Apresenta hipótese pré-silábica ou encontra-se em transição inicial"], "prompts": ["Descreva como foi a observação da escrita espontânea desta criança: o que ela produziu, como reagiu à proposta e o que essa escrita revela sobre sua hipótese atual?"]}, {"title": "12. Numerais, Contagem, Quantificação e Operações Iniciais", "bncc": "BNCC: EI03ET01, EI03ET04, EI03ET05, EI03ET07, EI03ET08 | Campo: Espaços, tempos, quantidades, relações e transformações", "checklist": [], "prompts": ["Observações sobre escrita emergente:"]}, {"title": "13. Formas, Geometria Inicial, Classificação, Seriação e Padrões", "bncc": "BNCC: EI03ET01, EI03ET05, EI03ET08, EI03TS02 | Campos: Espaços, tempos, quantidades, relações e transformações; Traços, sons, cores e formas", "checklist": ["Recita a sequência oral até 10 com maior ou menor estabilidade", "Reconhece alguns numerais visualmente", "Nomeia alguns numerais", "Conta pequenas coleções com apoio, ainda podendo pular ou repetir elementos", "Associa pequenas quantidades a numeral em situações muito concretas", "Responde ''quantos?'' em coleções pequenas após contar", "Compara ''mais'' e ''menos'' em contextos concretos", "Separa 1, 2, 3 ou 4 objetos quando solicitado em situações apoiadas"], "prompts": ["Até qual número esta criança conta com segurança? Ela usa os dedos ou objetos como apoio para a contagem?", "Observações sobre numerais, contagem e quantificação:"]}, {"title": "14. Noções Espaço-Temporais, Calendário, Dias da Semana e Rotina", "bncc": "BNCC: EI03ET03, EI03ET04, EI03ET07, EI03EO03 | Campos: Espaços, tempos, quantidades, relações e transformações; O eu, o outro e o nós", "checklist": ["Identifica círculo, quadrado e triângulo em materiais e objetos do cotidiano", "Nomeia algumas formas geométricas básicas", "Faz pareamento de formas iguais", "Classifica por um critério: cor, forma ou tamanho", "Ordena poucos elementos por tamanho com apoio", "Reconhece sequências simples e completa padrões concretos curtos", "Percebe semelhanças e diferenças entre objetos e figuras"], "prompts": ["Como a criança reage a atividades de classificação e padrões? Ela consegue explicar por que agrupou objetos de determinada maneira?", "Observações sobre geometria, classificação e padrões:"]}, {"title": "15. Investigação, Observação, Memória Cognitiva e Raciocínio", "bncc": "BNCC: EI03ET02, EI03ET03, EI03ET04, EI03ET05, EI03EF01 | Campos: Espaços, tempos, quantidades, relações e transformações; Escuta, fala, pensamento e imaginação", "checklist": ["Reconhece a rotina da turma e a sequência geral do dia", "Compreende antes/depois e começo/fim em situações concretas", "Identifica dia/noite em situações do cotidiano", "Participa do calendário com ajuda do adulto", "Acompanha a sequência da semana quando apoiada por cartazes, músicas ou marcações", "Reconhece ''hoje'' em contexto muito concreto, ligado à rotina imediata", "Localiza objetos e pessoas por referências espaciais simples: dentro/fora, em cima/embaixo, perto/longe, frente/atrás"], "prompts": ["Como a criança demonstra compreender a rotina do dia? Ela antecipa o que vem a seguir? Usa noções espaciais corretamente em situações do cotidiano?", "Observações sobre noções espaço-temporais e rotina:"]}, {"title": "16. Expressão Artística, Musical, Corporal e Imaginação Simbólica", "bncc": "BNCC: EI03TS01, EI03TS02, EI03TS03, EI03EF06, EI03CG01 | Campos: Traços, sons, cores e formas; Escuta, fala, pensamento e imaginação; Corpo, gestos e movimentos", "checklist": ["Observa fenômenos, materiais e experiências com curiosidade", "Faz perguntas simples sobre o que vê, percebe ou estranha", "Compara objetos por características concretas: cor, tamanho, forma, textura", "Agrupa objetos iguais e reconhece o que está faltando em conjuntos simples", "Recorda informações recentes com ajuda", "Acompanha pequenas investigações orientadas pelo adulto"], "prompts": ["Esta criança demonstra curiosidade e interesse por investigar? Ela costuma fazer perguntas sobre o que observa? Dê um exemplo recente:", "Observações sobre investigação, raciocínio e memória cognitiva:"]}, {"title": "CONSIDERAÇÕES GERAIS E SÍNTESE PARA O RELATÓRIO", "bncc": "", "checklist": ["Participa de canções, parlendas, brincadeiras cantadas e jogos musicais", "Acompanha gestos em músicas e brincadeiras", "Explora sons produzidos pelo corpo, objetos e instrumentos simples", "Desenha e dramatiza espontaneamente situações do cotidiano", "Participa de faz de conta e atribui papéis simples em brincadeiras simbólicas", "Usa materiais diversos em produções simples e demonstra prazer em experimentar linguagens", "Participa de momentos de apreciação artística e musical com atenção", "Observa e comenta produções próprias e dos colegas", "Expressa preferências estéticas (cores, materiais, estilos)"], "prompts": ["Como esta criança se engaja no faz de conta e nas brincadeiras simbólicas? Ela cria enredos, distribui papéis, usa objetos de forma imaginativa?", "Observações sobre expressão artística, musical e simbólica:"]}]'::jsonb);

-- Infantil 5 | 2º Semestre | 16 seções | 148 checklist | 48 texto
INSERT INTO qsi_templates (serie, semestre, titulo, subtitulo, sections)
VALUES ('Infantil 5', 2, 'Questionário de Sondagem — Infantil 5', 'Instrumento para levantamento do desenvolvimento da criança ao final do ano letivo', '[{"title": "1. Identidade, Autonomia, Convivência e Regulação Emocional", "bncc": "BNCC: EI03EO01, EI03EO02, EI03EO03, EI03EO04, EI03EO06 | Campos: O eu, o outro e o nós; Corpo, gestos e movimentos", "checklist": ["Diz o próprio nome completo e reconhece dados pessoais básicos (idade, turma)", "Identifica colegas e adultos de referência pelo nome, demonstrando vínculos de amizade", "Guarda e organiza seus pertences com autonomia crescente, sem necessidade de lembrete constante", "Participa de rodas de conversa contribuindo com opiniões e relatos, permanecendo no grupo por períodos mais longos", "Espera a sua vez em jogos, fala e uso de materiais, demonstrando maior autocontrole", "Compartilha brinquedos e materiais com colegas, negociando com menos intervenção do adulto", "Segue combinados da turma com maior consistência, lembrando-se deles em situações novas", "Reconhece e nomeia emoções em si e nos outros, buscando estratégias simples para lidar com elas", "Verbaliza desejos, incômodos e necessidades com clareza, usando a fala como recurso principal", "Resolve conflitos simples entre colegas com mediação mínima, tentando dialogar antes de recorrer ao adulto", "Tolera frustrações com maior equilíbrio, retomando a atividade sem necessidade de acolhimento prolongado", "Realiza a rotina com crescente autonomia: lanche, higiene, organização, fila, banheiro", "Aceita mudanças na rotina com flexibilidade, adaptando-se sem desorganização significativa"], "prompts": ["Comparando com o início do ano, quais avanços mais significativos você observa na autonomia e na convivência desta criança? Dê exemplos concretos.", "Descreva como esta criança lida atualmente com situações de frustração ou conflito com colegas. Houve evolução em relação ao 1º semestre?", "Observações sobre autonomia, convivência e regulação emocional (inclua alimentação, sono, higiene):"]}, {"title": "2. Coordenação Motora Ampla, Esquema Corporal e Lateralidade", "bncc": "BNCC: EI03CG01, EI03CG02, EI03CG03, EI03CG05, EI03ET04 | Campos: Corpo, gestos e movimentos; Espaços, tempos, quantidades, relações e transformações", "checklist": ["Corre com coordenação, mudando de direção e velocidade com controle", "Para após correr com equilíbrio, sem perder a estabilidade", "Pula com os dois pés e em um pé só por breves momentos", "Salta obstáculos de alturas variadas e desce desníveis com segurança", "Sobe e desce escadas alternando os pés com equilíbrio", "Anda em linha, trilha ou circuito com controle e equilíbrio", "Chuta bola com direção intencional e arremessa bola com força e direção", "Recebe bola com as mãos e braços de forma mais coordenada", "Reproduz sequências de movimentos em brincadeiras, danças e circuitos", "Reconhece, nomeia e localiza partes do corpo, inclusive articulações", "Executa comandos motores compostos: ''pula e gira'', ''corre e para'', ''abaixa e levanta''", "Demonstra preferência lateral (mão, pé) com maior consistência", "Utiliza noções de direita/esquerda no próprio corpo em situações dirigidas"], "prompts": ["Comparando com o início do ano, quais conquistas motoras se destacam? A criança demonstra maior confiança e coordenação?", "Há definição clara de lateralidade (mão/pé dominante)? Descreva o que observa.", "Observações sobre movimento, esquema corporal e lateralidade:"]}, {"title": "3. Coordenação Motora Fina, Manipulação e Autonomia Manual", "bncc": "BNCC: EI03CG05, EI03TS02, EI03TS03 | Campos: Corpo, gestos e movimentos; Traços, sons, cores e formas", "checklist": ["Segura lápis, giz, pincel ou canetão com preensão trípode ou em transição para trípode", "Abre e fecha potes, tampas, zíperes, caixas e presilhas com autonomia", "Encaixa peças pequenas, rosqueia, monta e desmonta jogos com precisão crescente", "Usa pinça com destreza para pegar objetos pequenos e manipular materiais delicados", "Modela massinha com formas intencionais: bolinhas, cobrinhas, achatados, figuras simples", "Rasga papel em tiras e pedaços controlados, colando com quantidade adequada de cola", "Dobra papel seguindo marcas e instruções simples", "Distribui cola com maior controle de quantidade", "Usa tesoura com coordenação funcional, recortando em linha reta e formas simples", "Permanece em atividade de mesa por períodos mais longos, com menor necessidade de redirecionamento"], "prompts": ["Como evoluiu a preensão ao longo do ano? A criança já utiliza preensão trípode? Há dificuldades persistentes?", "A criança consegue usar tesoura para recortar formas? Descreva o nível de controle observado.", "Observações sobre coordenação fina e manipulação:"]}, {"title": "4. Grafomotricidade, Traçado e Organização Espacial no Papel", "bncc": "BNCC: EI03CG05, EI03TS02, EI03EF09 | Campos: Corpo, gestos e movimentos; Traços, sons, cores e formas; Escuta, fala, pensamento e imaginação", "checklist": ["Faz traços verticais, horizontais, inclinados, curvos e ondulados com maior precisão", "Cobre pontilhados e liga pontos com controle do traçado", "Faz traçados em suportes variados mantendo direção e fluidez", "Desenha e escreve com intenção, organizando elementos no espaço do papel", "Copia formas simples (círculo, quadrado, triângulo, cruz) a partir de modelo com fidelidade crescente", "Ocupa o espaço do papel de forma mais planejada, distribuindo elementos", "Mantém direção do traço com maior estabilidade (esquerda-direita, cima-baixo)", "Respeita margens, limites e alinhamentos visuais com menor necessidade de apoio", "Tenta reproduzir letras e numerais com traçado próprio"], "prompts": ["Comparando com o 1º semestre, como evoluiu a organização espacial no papel? A criança já respeita margens e distribui elementos?", "A criança já tenta reproduzir letras ou numerais espontaneamente? Descreva o traçado observado.", "Observações sobre grafomotricidade e traçado:"]}, {"title": "5. Desenho, Pintura, Recorte, Colagem e Composição Visual", "bncc": "BNCC: EI03TS01, EI03TS02, EI03TS03, EI03CG05 | Campos: Traços, sons, cores e formas; Corpo, gestos e movimentos", "checklist": ["Desenha espontaneamente com riqueza crescente de detalhes e elementos", "Representa figuras humanas com cabeça, tronco, membros e detalhes faciais", "Cria cenas com múltiplos elementos: pessoas, objetos, cenários, sol, chão, céu", "Diferencia claramente desenho de escrita e usa ambos de forma intencional", "Explora tinta, pincel, rolinho, esponja e outros instrumentos com controle", "Reconhece, nomeia e escolhe cores com intenção estética, incluindo misturas simples", "Pinta dentro de contornos com maior precisão, extrapolando menos os limites", "Usa tesoura para recortar formas simples e figuras de revistas", "Cola figuras e materiais com posicionamento intencional na composição", "Participa de produções coletivas e individuais com criatividade e iniciativa"], "prompts": ["Quais avanços você observa no desenho desta criança ao longo do ano? O que aparece agora que não aparecia antes?", "A criança demonstra estilo próprio ou preferências estéticas marcantes em suas produções?", "Observações sobre expressão visual e produção artística:"]}, {"title": "6. Percepção Visual, Discriminação, Memória Visual e Organização Perceptiva", "bncc": "BNCC: EI03TS02, EI03ET01, EI03ET05 | Campos: Traços, sons, cores e formas; Espaços, tempos, quantidades, relações e transformações", "checklist": ["Reconhece igual e diferente em figuras com detalhes sutis", "Encontra pares em jogos de memória com maior número de peças", "Identifica e nomeia cores, formas geométricas e suas variações", "Percebe detalhes em imagens, cenas e objetos, descrevendo o que observa", "Monta quebra-cabeças com número crescente de peças (10-20 peças)", "Completa sequências visuais e padrões com autonomia crescente", "Reconhece letras e numerais familiares com maior segurança", "Observa modelos e os reproduz mantendo correspondência visual mais fiel"], "prompts": ["Houve evolução na capacidade de concentração em jogos de memória e atividades de discriminação visual?", "A criança consegue observar um modelo e reproduzi-lo? Descreva o nível de fidelidade.", "Observações sobre percepção e discriminação visual:"]}, {"title": "7. Atenção, Memória e Funções Executivas", "bncc": "BNCC: EI03EO02, EI03EO03, EI03EF01, EI03EF07, EI03ET04 | Campos: O eu, o outro e o nós; Escuta, fala, pensamento e imaginação; Espaços, tempos, quantidades, relações e transformações", "checklist": ["Mantém atenção em atividades dirigidas por períodos mais longos que no início do ano", "Necessita de menos redirecionamentos para manter-se na tarefa", "Segue instruções de duas ou mais etapas com compreensão", "Lembra combinados e regras da turma sem necessidade de lembrete constante", "Recorda acontecimentos, aprendizagens e experiências vividas ao longo do semestre", "Organiza materiais e inicia atividades com maior autonomia", "Transita entre tarefas com maior flexibilidade, inclusive em situações de interrupção", "Demonstra controle inibitório crescente: espera, pensa antes de agir, contém impulsos", "Ouve toda a orientação antes de agir na maioria das situações"], "prompts": ["Comparando com o início do ano, como evoluiu a capacidade de atenção e autorregulação desta criança?", "Quais estratégias continuam sendo necessárias para apoiar o foco? Há momentos do dia em que a atenção é melhor ou pior?", "Observações sobre atenção, memória e autorregulação:"]}, {"title": "8. Linguagem Oral, Compreensão, Narrativa e Comunicação", "bncc": "BNCC: EI03EF01, EI03EF03, EI03EF04, EI03EF06, EI03EF07, EI03EO04 | Campos: Escuta, fala, pensamento e imaginação; O eu, o outro e o nós", "checklist": ["Fala frases completas e complexas, com uso de conectivos (porque, então, depois)", "Nomeia objetos, pessoas, ações, sentimentos e situações com vocabulário ampliado", "Responde perguntas elaboradas: ''por quê?'', ''como?'', ''quando?'', além de ''quem?'', ''o quê?'', ''onde?''", "Compreende histórias com enredo e identifica personagens, cenário e ações principais", "Relata fatos, vivências e sequências de acontecimentos com organização temporal", "Participa de diálogos respeitando turnos de fala por períodos maiores", "Usa vocabulário diversificado, incorporando palavras aprendidas em histórias e conversas", "Reconta histórias com sequência lógica, com ou sem apoio de imagens", "Argumenta, justifica e defende opiniões em situações do cotidiano"], "prompts": ["Comparando com o início do ano, como evoluiu a comunicação oral? A criança argumenta, justifica, cria narrativas?", "Há algo no repertório de linguagem que chama atenção (trocas fonológicas persistentes, fluência, vocabulário)?", "Observações sobre linguagem oral e comunicação:"]}, {"title": "9. Consciência Fonológica e Análise Sonora da Fala", "bncc": "BNCC: EI03EF02, EI03EF03, EI03EF08, EI03EF09 | Campos: Escuta, fala, pensamento e imaginação", "checklist": ["Percebe e produz rimas em cantigas, parlendas e jogos orais", "Completa rimas e refrões com autonomia", "Diferencia palavras grandes e pequenas com consciência oral", "Segmenta palavras em sílabas batendo palmas com autonomia", "Identifica sílaba ou som inicial de palavras familiares sem necessidade de pistas visuais", "Compara e agrupa palavras que começam com o mesmo som", "Identifica palavras que terminam com o mesmo som (rima de produção)", "Demonstra prazer e engajamento em jogos sonoros, trava-línguas e brincadeiras fonológicas"], "prompts": ["Comparando com o 1º semestre, a criança avançou na percepção dos sons da fala? Ela já segmenta sílabas e percebe rimas com autonomia?", "A criança consegue identificar o som inicial de palavras? Ela relaciona som e letra? Descreva.", "Observações sobre consciência fonológica:"]}, {"title": "10. Conhecimento do Nome, Alfabeto e Relação Letra/Som", "bncc": "BNCC: EI03EF01, EI03EF03, EI03EF08, EI03EF09, EI03EO04 | Campos: Escuta, fala, pensamento e imaginação; O eu, o outro e o nós", "checklist": ["Reconhece o próprio nome escrito com segurança e o diferencia de nomes semelhantes", "Escreve o próprio nome com autonomia, de memória", "Identifica e nomeia a maioria das letras do próprio nome e de nomes dos colegas", "Reconhece um número significativo de letras do alfabeto em diferentes contextos", "Diferencia letras de números, desenhos e símbolos com segurança", "Nomeia letras com maior estabilidade e consistência", "Associa letra ao som inicial de palavras familiares", "Identifica vogais e consoantes frequentes com segurança crescente", "Demonstra interesse por palavras do ambiente e tenta lê-las"], "prompts": ["Quais letras esta criança reconhece e nomeia com segurança ao final do ano? Houve ampliação em relação ao 1º semestre?", "A criança escreve o próprio nome de memória? Com todas as letras? Com letras maiúsculas, minúsculas ou misturadas?", "Observações sobre conhecimento do alfabeto e relação letra/som:"]}, {"title": "11. Escrita Emergente e Evolução das Hipóteses de Escrita", "bncc": "BNCC: EI03EF01, EI03EF06, EI03EF08, EI03EF09, EI03TS02 | Campos: Escuta, fala, pensamento e imaginação; Traços, sons, cores e formas", "checklist": ["Reconhece que a escrita tem função social e a utiliza em brincadeiras e projetos", "Diferencia claramente desenho de escrita e produz ambos intencionalmente", "Faz escrita espontânea usando letras convencionais, ainda que sem correspondência sonora estável", "Escreve o próprio nome de memória com todas ou quase todas as letras", "Tenta escrever outras palavras além do próprio nome", "Começa a estabelecer relação entre partes sonoras e partes gráficas da escrita", "Apresenta hipótese silábica (com ou sem valor sonoro) ou encontra-se em transição", "Demonstra interesse em saber o que está escrito em textos do ambiente"], "prompts": ["Comparando com o 1º semestre, como evoluiu a escrita espontânea desta criança? Descreva a produção atual e o que ela revela sobre a hipótese de escrita.", "A criança tenta escrever palavras além do próprio nome? Quais? Com que estratégias?", "Observações sobre escrita emergente e hipóteses de escrita:"]}, {"title": "12. Numerais, Contagem, Quantificação e Operações Iniciais", "bncc": "BNCC: EI03ET01, EI03ET04, EI03ET05, EI03ET07, EI03ET08 | Campos: Espaços, tempos, quantidades, relações e transformações", "checklist": ["Recita a sequência oral até 20 ou mais com estabilidade crescente", "Reconhece numerais de 0 a 10 visualmente com segurança", "Nomeia numerais de 0 a 10 com consistência", "Conta coleções de até 10 objetos com correspondência biunívoca (um a um)", "Associa quantidade ao numeral correspondente em situações concretas", "Responde ''quantos?'' após contar, demonstrando compreensão de cardinalidade", "Compara quantidades usando ''mais'', ''menos'' e ''igual''", "Resolve situações-problema simples de juntar e tirar com material concreto", "Separa quantidades solicitadas (até 10) com autonomia crescente", "Tenta registrar quantidades com desenhos, traços ou numerais"], "prompts": ["Até qual número esta criança conta com correspondência biunívoca (um a um)? Ela já compreende cardinalidade?", "A criança resolve situações-problema de juntar e tirar? Dê um exemplo de como ela raciocina.", "Observações sobre numerais, contagem e quantificação:"]}, {"title": "13. Formas, Geometria Inicial, Classificação, Seriação e Padrões", "bncc": "BNCC: EI03ET01, EI03ET05, EI03ET08, EI03TS02 | Campos: Espaços, tempos, quantidades, relações e transformações; Traços, sons, cores e formas", "checklist": ["Identifica e nomeia círculo, quadrado, triângulo e retângulo em materiais e objetos", "Reconhece formas geométricas em diferentes posições e tamanhos", "Faz pareamento de formas iguais e diferentes com segurança", "Classifica por dois critérios simultâneos: cor e forma, cor e tamanho", "Ordena elementos por tamanho (do menor ao maior e vice-versa) com autonomia crescente", "Reconhece, completa e cria padrões de sequências (AB, ABC)", "Percebe simetria em objetos e figuras simples", "Explica por que agrupou objetos de determinada maneira"], "prompts": ["A criança consegue classificar por dois critérios ao mesmo tempo? Ela verbaliza o raciocínio?", "Comparando com o 1º semestre, houve evolução na compreensão de padrões e sequências?", "Observações sobre geometria, classificação e padrões:"]}, {"title": "14. Noções Espaço-Temporais, Calendário, Dias da Semana e Rotina", "bncc": "BNCC: EI03ET03, EI03ET04, EI03ET07, EI03EO03 | Campos: Espaços, tempos, quantidades, relações e transformações; O eu, o outro e o nós", "checklist": ["Reconhece e descreve a rotina da turma, antecipando o que vem a seguir", "Compreende e usa noções temporais: antes/depois, ontem/hoje/amanhã, começo/fim", "Identifica dia/noite e relaciona com atividades do cotidiano", "Participa do calendário com compreensão crescente de dia, mês e dia da semana", "Nomeia os dias da semana na sequência, com ou sem apoio", "Reconhece ''hoje'', ''ontem'' e ''amanhã'' com maior consistência", "Utiliza referências espaciais com precisão: dentro/fora, em cima/embaixo, perto/longe, frente/atrás, ao lado", "Descreve posições e trajetórias usando linguagem espacial"], "prompts": ["A criança demonstra compreender e antecipar a rotina? Ela usa noções temporais corretamente (ontem, amanhã)?", "Como está o uso de noções espaciais? A criança descreve posições e trajetórias corretamente?", "Observações sobre noções espaço-temporais e rotina:"]}, {"title": "15. Investigação, Observação, Memória Cognitiva e Raciocínio", "bncc": "BNCC: EI03ET02, EI03ET03, EI03ET04, EI03ET05, EI03EF01 | Campos: Espaços, tempos, quantidades, relações e transformações; Escuta, fala, pensamento e imaginação", "checklist": ["Observa fenômenos e experiências com curiosidade ativa e questionamento", "Faz perguntas elaboradas sobre o que vê, percebe ou estranha, incluindo ''por quê?''", "Compara objetos por múltiplas características: cor, tamanho, forma, textura, peso", "Agrupa, classifica e justifica agrupamentos com linguagem própria", "Recorda informações de experiências anteriores e as aplica em situações novas", "Formula hipóteses simples e testa ideias em investigações orientadas", "Registra observações por meio de desenhos ou tentativas de escrita"], "prompts": ["Comparando com o início do ano, como evoluiu a curiosidade investigativa desta criança? Ela formula hipóteses?", "Dê um exemplo recente de investigação ou raciocínio demonstrado por esta criança.", "Observações sobre investigação, raciocínio e memória cognitiva:"]}, {"title": "16. Expressão Artística, Musical, Corporal e Imaginação Simbólica", "bncc": "BNCC: EI03TS01, EI03TS02, EI03TS03, EI03EF06, EI03CG01 | Campos: Traços, sons, cores e formas; Escuta, fala, pensamento e imaginação; Corpo, gestos e movimentos", "checklist": ["Participa de canções, parlendas e jogos musicais com engajamento e memória das letras", "Reproduz sequências de gestos em músicas e coreografias", "Explora sons do corpo, objetos e instrumentos com intenção musical", "Cria enredos elaborados no faz de conta, com distribuição de papéis e diálogos", "Usa objetos de forma simbólica e criativa em brincadeiras imaginárias", "Usa materiais diversos em produções artísticas com iniciativa e criatividade", "Aprecia produções artísticas e musicais, comentando o que observa", "Observa e comenta produções próprias e dos colegas com vocabulário estético", "Expressa preferências estéticas e justifica escolhas"], "prompts": ["Como evoluiu o faz de conta desta criança ao longo do ano? Os enredos ficaram mais complexos?", "Quais linguagens artísticas (música, dança, teatro, artes visuais) mais mobilizam esta criança? Houve ampliação de repertório?", "Observações sobre expressão artística, musical e simbólica:"]}]'::jsonb);

